window.bibleReaderData = window.bibleReaderData || {chapters:{}};
window.bibleReaderData.chapters = window.bibleReaderData.chapters || {};
window.bibleReaderData.chapters['MAT'] = window.bibleReaderData.chapters['MAT'] || {};
(function(chapters){ for (const c in chapters){ window.bibleReaderData.chapters['MAT'][c]=window.bibleReaderData.chapters['MAT'][c]||{}; Object.assign(window.bibleReaderData.chapters['MAT'][c], chapters[c]); } })({"1":{"fa":[{"v":1,"t":"کتاب نسب نامه عیسی مسیح بن داود بن ابراهیم:"},{"v":2,"t":"ابراهیم اسحاق را آورد و اسحاق یعقوب را آورد و یعقوب یهودا و برادران او راآورد."},{"v":3,"t":"و یهودا، فارص و زارح را از تامار آورد وفارص، حصرون را آورد و حصرون، ارام را آورد."},{"v":4,"t":"و ارام، عمیناداب را آورد و عمیناداب، نحشون را آورد و نحشون، شلمون را آورد."},{"v":5,"t":"وشلمون، بوعز را از راحاب آورد و بوعز، عوبیدرا از راعوت آورد و عوبید، یسا را آورد."},{"v":6,"t":"ویسا داود پادشاه را آورد و داود پادشاه، سلیمان را از زن اوریا آورد."},{"v":7,"t":"و سلیمان، رحبعام را آورد و رحبعام، ابیا را آورد و ابیا، آسا راآورد."},{"v":8,"t":"و آسا، یهوشافاط را آورد و یهوشافاط، یورام را آورد و یورام، عزیا را آورد."},{"v":9,"t":"و عزیا، یوتام را آورد و یوتام، احاز را آورد و احاز، حزقیا را آورد."},{"v":10,"t":"و حزقیا، منسی را آورد ومنسی، آمون را آورد و آمون، یوشیا را آورد."},{"v":11,"t":"ویوشیا، یکنیا و برادرانش را در زمان جلای بابل آورد."},{"v":12,"t":"و بعد از جلای بابل، یکنیا، سالتیئل را آورد و سالتیئیل، زروبابل را آورد."},{"v":13,"t":"زروبابل، ابیهود را آورد و ابیهود، ایلیقایم را آورد و ایلیقایم، عازور را آورد."},{"v":14,"t":"و عازور، صادوق را آورد و صادوق، یاکین را آورد و یاکین، ایلیهود را آورد."},{"v":15,"t":"و ایلیهود، ایلعازر را آوردو ایلعازر، متان را آورد و متان، یعقوب راآورد."},{"v":16,"t":"و یعقوب، یوسف شوهر مریم راآورد که عیسی مسمی به مسیح از او متولدشد."},{"v":17,"t":"پس تمام طبقات، از ابراهیم تا داودچهارده طبقه است، و از داود تا جلای بابل چهارده طبقه، و از جلای بابل تا مسیح چهارده طبقه."},{"v":18,"t":"اما ولادت عیسی مسیح چنین بود که چون مادرش مریم به یوسف نامزد شده بود، قبل ازآنکه با هم آیند، او را از روح‌القدس حامله یافتند."},{"v":19,"t":"و شوهرش یوسف چونکه مرد صالح بود ونخواست او را عبرت نماید، پس اراده نمود او رابه پنهانی رها کند."},{"v":20,"t":"اما چون او در این چیزهاتفکر می‌کرد، ناگاه فرشته خداوند در خواب بروی ظاهر شده، گفت: «ای یوسف پسر داود، ازگرفتن زن خویش مریم مترس، زیرا که آنچه دروی قرار گرفته است، از روح‌القدس است،"},{"v":21,"t":"و اوپسری خواهد زایید و نام او را عیسی خواهی نهاد، زیرا که او امت خویش را از گناهانشان خواهد رهانید.»"},{"v":22,"t":"و این همه برای آن واقع شد تاکلامی که خداوند به زبان نبی گفته بود، تمام گردد"},{"v":23,"t":"«که اینک باکره آبستن شده پسری خواهدزایید و نام او را عمانوئیل خواهند خواند که تفسیرش این است: خدا با ما.»"},{"v":24,"t":"پس چون یوسف از خواب بیدار شد، چنانکه فرشته خداوند بدو امر کرده بود، بعمل آورد و زن خویش را گرفت"},{"v":25,"t":"و تا پسر نخستین خود رانزایید، او را نشناخت؛ و او را عیسی نام نهاد."}]},"2":{"fa":[{"v":1,"t":"و چون عیسی در ایام هیرودیس پادشاه دربیت لحم یهودیه تولد یافت، ناگاه مجوسی چند از مشرق به اورشلیم آمده، گفتند:"},{"v":2,"t":"«کجاست آن مولود که پادشاه یهود است زیراکه ستاره او را در مشرق دیده‌ایم و برای پرستش او آمده‌ایم؟»"},{"v":3,"t":"اما هیرودیس پادشاه چون این راشنید، مضطرب شد و تمام اورشلیم با وی."},{"v":4,"t":"پس همه روسای کهنه و کاتبان قوم را جمع کرده، ازایشان پرسید که «مسیح کجا باید متولد شود؟»"},{"v":5,"t":"بدو گفتند: «در بیت لحم یهودیه زیرا که از نبی چنین مکتوب است:"},{"v":6,"t":"و تو‌ای بیت لحم، در زمین یهودا از سایر سرداران یهودا هرگز کوچکترنیستی، زیرا که از تو پیشوایی به ظهور خواهدآمد که قوم من اسرائیل را رعایت خواهد نمود.»"},{"v":7,"t":"آنگاه هیرودیس مجوسیان را در خلوت خوانده، وقت ظهور ستاره را از ایشان تحقیق کرد."},{"v":8,"t":"پس ایشان را به بیت لحم روانه نموده، گفت: «بروید و از احوال آن طفل بتدقیق تفحص کنید و چون یافتید مرا خبر دهید تا من نیز آمده، او را پرستش نمایم.»"},{"v":9,"t":"چون سخن پادشاه راشنیدند، روانه شدند که ناگاه آن ستاره‌ای که در مشرق دیده بودند، پیش روی ایشان می‌رفت تافوق آنجایی که طفل بود رسیده، بایستاد."},{"v":10,"t":"وچون ستاره را دیدند، بی‌نهایت شاد و خوشحال گشتند"},{"v":11,"t":"و به خانه درآمده، طفل را با مادرش مریم یافتند و به روی در‌افتاده، او را پرستش کردند و ذخایر خود را گشوده، هدایای طلا وکندر و مر به وی گذرانیدند."},{"v":12,"t":"و چون در خواب وحی بدیشان در‌رسید که به نزد هیرودیس بازگشت نکنند، پس از راه دیگر به وطن خویش مراجعت کردند."},{"v":13,"t":"و چون ایشان روانه شدند، ناگاه فرشته خداوند در خواب به یوسف ظاهر شده، گفت: «برخیز و طفل و مادرش را برداشته به مصر فرارکن و در آنجا باش تا به تو خبر دهم، زیرا که هیرودیس طفل را جستجو خواهد کرد تا او راهلاک نماید.»"},{"v":14,"t":"پس شبانگاه برخاسته، طفل ومادر او را برداشته، بسوی مصر روانه شد"},{"v":15,"t":"و تاوفات هیرودیس در آنجا بماند، تا کلامی که خداوند به زبان نبی گفته بود تمام گردد که «ازمصر پسر خود را خواندم.»"},{"v":16,"t":"چون هیرودیس دید که مجوسیان او را سخریه نموده‌اند، بسیارغضبناک شده، فرستاد و جمیع اطفالی را که دربیت لحم و تمام نواحی آن بودند، از دو ساله وکمتر موافق وقتی که از مجوسیان تحقیق نموده بود، به قتل رسانید."},{"v":17,"t":"آنگاه کلامی که به زبان ارمیای نبی گفته شده بود، تمام شد: «آوازی دررامه شنیده شد، گریه و زاری و ماتم عظیم که راحیل برای فرزندان خود گریه می‌کند و تسلی نمی پذیرد زیرا که نیستند.»"},{"v":18,"t":"اما چون هیرودیس وفات یافت، ناگاه فرشته خداوند در مصر به یوسف در خواب ظاهرشده، گفت:"},{"v":19,"t":"«برخیز و طفل و مادرش رابرداشته، به زمین اسرائیل روانه شو زیرا آنانی که قصد جان طفل داشتند فوت شدند.»"},{"v":20,"t":"پس برخاسته، طفل و مادر او را برداشت و به زمین اسرائیل آمد."},{"v":21,"t":"اما چون شنید که ارکلاوس به‌جای پدر خود هیرودیس بر یهودیه پادشاهی می‌کند، از رفتن بدان سمت ترسید و در خواب وحی یافته، به نواحی جلیل برگشت."},{"v":22,"t":"و آمده در بلده‌ای مسمی به ناصره ساکن شد، تا آنچه به زبان انبیا گفته شده بود تمام شود که «به ناصری خوانده خواهد شد.»"}]},"3":{"fa":[{"v":1,"t":"و در آن ایام، یحیی تعمید‌دهنده در بیابان یهودیه ظاهر شد و موعظه کرده، می‌گفت:"},{"v":2,"t":"«توبه کنید، زیرا ملکوت آسمان نزدیک است.»"},{"v":3,"t":"زیرا همین است آنکه اشعیای نبی از او خبرداده، می‌گوید: «صدای ندا کننده‌ای در بیابان که راه خداوند را مهیا سازید و طرق او را راست نمایید.»"},{"v":4,"t":"و این یحیی لباس از پشم شترمی داشت، و کمربند چرمی بر کمر و خوراک او ازملخ و عسل بری می‌بود."},{"v":5,"t":"در این وقت، اورشلیم و تمام یهودیه وجمیع حوالی اردن نزد او بیرون می‌آمدند،"},{"v":6,"t":"و به گناهان خود اعتراف کرده، در اردن از وی تعمیدمی یافتند."},{"v":7,"t":"پس چون بسیاری از فریسیان و صدوقیان رادید که بجهت تعمید وی می‌آیند، بدیشان گفت: «ای افعی‌زادگان، که شما را اعلام کرد که از غضب آینده بگریزید؟"},{"v":8,"t":"اکنون ثمره شایسته توبه بیاورید،"},{"v":9,"t":"و این سخن را به‌خاطر خود راه مدهیدکه پدر ما ابراهیم است، زیرا به شما می‌گویم خداقادر است که از این سنگها فرزندان برای ابراهیم برانگیزاند."},{"v":10,"t":"و الحال تیشه بر ریشه درختان نهاده شده است، پس هر درختی که ثمره نیکونیاورد، بریده و در آتش افکنده شود."},{"v":11,"t":"من شمارا به آب به جهت توبه تعمید می‌دهم. لکن او که بعد از من می‌آید از من تواناتر است که لایق برداشتن نعلین او نیستم؛ او شما را به روح‌القدس و آتش تعمید خواهد داد."},{"v":12,"t":"او غربال خود را دردست دارد و خرمن خود را نیکو پاک کرده، گندم خویش را در انبار ذخیره خواهد نمود، ولی کاه رادر آتشی که خاموشی نمی پذیرد خواهدسوزانید.»"},{"v":13,"t":"آنگاه عیسی از جلیل به اردن نزد یحیی آمدتا از او تعمید یابد."},{"v":14,"t":"اما یحیی او را منع نموده، گفت: «من احتیاج دارم که از تو تعمید یابم و تونزد من می‌آیی؟»"},{"v":15,"t":"عیسی در جواب وی گفت: «الان بگذارزیرا که ما را همچنین مناسب است تا تمام عدالت را به‌کمال رسانیم.»"},{"v":16,"t":"اما عیسی چون تعمیدیافت، فور از آب برآمد که در ساعت آسمان بروی گشاده شد و روح خدا را دید که مثل کبوتری نزول کرده، بر وی می‌آید."},{"v":17,"t":"آنگاه خطابی ازآسمان در‌رسید که «این است پسر حبیب من که ازاو خشنودم.»"}]},"4":{"fa":[{"v":1,"t":"آنگاه عیسی به‌دست روح به بیابان برده شدتا ابلیس او را تجربه نماید."},{"v":2,"t":"و چون چهل شبانه‌روز روزه داشت، آخر گرسنه گردید."},{"v":3,"t":"پس تجربه کننده نزد او آمده، گفت: «اگر پسر خداهستی، بگو تا این سنگها نان شود.»"},{"v":4,"t":"در جواب گفت: «مکتوب است انسان نه محض نان زیست می‌کند، بلکه به هر کلمه‌ای که از دهان خدا صادرگردد.»"},{"v":5,"t":"آنگاه ابلیس او را به شهر مقدس برد و برکنگره هیکل برپا داشته،"},{"v":6,"t":"به وی گفت: «اگر پسرخدا هستی، خود را به زیر انداز، زیرا مکتوب است که فرشتگان خود را درباره تو فرمان دهد تاتو را به‌دستهای خود برگیرند، مبادا پایت به سنگی خورد.»"},{"v":7,"t":"عیسی وی را گفت: «و نیزمکتوب است خداوند خدای خود را تجربه مکن.»"},{"v":8,"t":"پس ابلیس او را به کوهی بسیار بلند برد وهمه ممالک جهان و جلال آنها را بدو نشان داده،"},{"v":9,"t":"به وی گفت: «اگر افتاده مرا سجده کنی، همانا این همه را به تو بخشم.»"},{"v":10,"t":"آنگاه عیسی وی راگفت: «دور شو‌ای شیطان، زیرا مکتوب است که خداوند خدای خود را سجده کن و او را فقطعبادت نما.»"},{"v":11,"t":"در ساعت ابلیس او را رها کرد واینک فرشتگان آمده، او را پرستاری می‌نمودند."},{"v":12,"t":"و چون عیسی شنید که یحیی گرفتار شده است، به جلیل روانه شد،"},{"v":13,"t":"و ناصره را ترک کرده، آمد و به کفرناحوم، به کناره دریا در حدودزبولون و نفتالیم ساکن شد."},{"v":14,"t":"تا تمام گردد آنچه به زبان اشعیای نبی گفته شده بود"},{"v":15,"t":"که «زمین زبولون و زمین نفتالیم، راه دریا آن طرف اردن، جلیل امت‌ها؛"},{"v":16,"t":"قومی که در ظلمت ساکن بودند، نوری عظیم دیدند و برنشینندگان دیار موت وسایه آن نوری تابید.»"},{"v":17,"t":"از آن هنگام عیسی به موعظه شروع کرد و گفت: «توبه کنید زیراملکوت آسمان نزدیک است.»"},{"v":18,"t":"و چون عیسی به کناره دریای جلیل می‌خرامید، دو برادر یعنی شمعون مسمی به پطرس و برادرش اندریاس را دید که دامی دردریا می‌اندازند، زیرا صیاد بودند."},{"v":19,"t":"بدیشان گفت: «از عقب من آیید تا شما را صیاد مردم گردانم.»"},{"v":20,"t":"در ساعت دامها را گذارده، از عقب او روانه شدند."},{"v":21,"t":"و چون از آنجا گذشت دو برادردیگر یعنی یعقوب، پسر زبدی و برادرش یوحنارا دید که در کشتی با پدر خویش زبدی، دامهای خود را اصلاح می‌کنند؛ ایشان را نیز دعوت نمود."},{"v":22,"t":"در حال، کشتی و پدر خود را ترک کرده، از عقب او روانه شدند."},{"v":23,"t":"و عیسی در تمام جلیل می‌گشت و درکنایس ایشان تعلیم داده، به بشارت ملکوت موعظه همی نمود و هر مرض و هر درد قوم راشفا می‌داد."},{"v":24,"t":"و اسم او در تمام سوریه شهرت یافت، و جمیع مریضانی که به انواع امراض ودردها مبتلا بودند و دیوانگان و مصروعان ومفلوجان را نزد او آوردند، و ایشان را شفا بخشید."},{"v":25,"t":"و گروهی بسیار از جلیل و دیکاپولس واورشلیم و یهودیه و آن طرف اردن در عقب اوروانه شدند."}]},"5":{"fa":[{"v":1,"t":"خوشابحالها و گروهی بسیار دیده، بر فراز کوه آمد و وقتی که او بنشست شاگردانش نزد اوحاضر شدند."},{"v":2,"t":"آنگاه دهان خود را گشوده، ایشان را تعلیم داد و گفت:"},{"v":3,"t":"«خوشابحال مسکینان در روح، زیرا ملکوت آسمان از آن ایشان است."},{"v":4,"t":"خوشابحال ماتمیان، زیرا ایشان تسلی خواهند یافت."},{"v":5,"t":"خوشابحال حلیمان، زیرا ایشان وارث زمین خواهند شد."},{"v":6,"t":"خوشابحال گرسنگان و تشنگان عدالت، زیراایشان سیر خواهندشد."},{"v":7,"t":"خوشابحال رحم کنندگان، زیرا بر ایشان رحم کرده خواهدشد."},{"v":8,"t":"خوشابحال پاک دلان، زیرا ایشان خدا راخواهند دید."},{"v":9,"t":"خوشابحال صلح کنندگان، زیراایشان پسران خدا خوانده خواهند شد."},{"v":10,"t":"خوشابحال زحمت کشان برای عدالت، زیراملکوت آسمان از آن ایشان است."},{"v":11,"t":"خوشحال باشید چون شما را فحش گویند و جفا رسانند، وبخاطر من هر سخن بدی بر شما کاذبانه گویند."},{"v":12,"t":"خوش باشید و شادی عظیم نمایید، زیرا اجر شما در آسمان عظیم است زیرا که به همینطور بر انبیای قبل از شما جفامی رسانیدند."},{"v":13,"t":"«شما نمک جهانید! لیکن اگر نمک فاسدگردد، به کدام چیز باز نمکین شود؟ دیگر مصرفی ندارد جز آنکه بیرون افکنده، پایمال مردم شود."},{"v":14,"t":"شما نور عالمید. شهری که بر کوهی بنا شود، نتوان پنهان کرد."},{"v":15,"t":"و چراغ را نمی افروزند تا آن را زیر پیمانه نهند، بلکه تا بر چراغدان گذارند؛ آنگاه به همه کسانی که در خانه باشند، روشنایی می‌بخشد."},{"v":16,"t":"همچنین بگذارید نور شما بر مردم بتابد تا اعمال نیکوی شما را دیده، پدر شما را که در آسمان است تمجید نمایند."},{"v":17,"t":"«گمان مبرید که آمده‌ام تا تورات یا صحف انبیا را باطل سازم. نیامده‌ام تا باطل نمایم بلکه تاتمام کنم."},{"v":18,"t":"زیرا هر آینه به شما می‌گویم، تاآسمان و زمین زایل نشود، همزه یا نقطه‌ای ازتورات هرگز زایل نخواهد شد تا همه واقع شود."},{"v":19,"t":"پس هر‌که یکی از این احکام کوچکترین رابشکند و به مردم چنین تعلیم دهد، در ملکوت آسمان کمترین شمرده شود. اما هر‌که بعمل آورد و تعلیم نماید، او در ملکوت آسمان بزرگ خوانده خواهد شد."},{"v":20,"t":"زیرا به شما می‌گویم، تاعدالت شما بر عدالت کاتبان و فریسیان افزون نشود، به ملکوت آسمان هرگز داخل نخواهیدشد."},{"v":21,"t":"«شنیده‌اید که به اولین گفته شده است “قتل مکن و هر‌که قتل کند سزاوار حکم شود.”"},{"v":22,"t":"لیکن من به شما می‌گویم، هر‌که به برادر خود بی‌سبب خشم گیرد، مستوجب حکم باشد و هر‌که برادرخود را راقا گوید، مستوجب قصاص باشد و هرکه احمق گوید، مستحق آتش جهنم بود."},{"v":23,"t":"پس هرگاه هدیه خود را به قربانگاه ببری و آنجا به‌خاطرت آید که برادرت بر تو حقی دارد،"},{"v":24,"t":"هدیه خود را پیش قربانگاه واگذار و رفته، اول با برادرخویش صلح نما و بعد آمده، هدیه خود رابگذران."},{"v":25,"t":"با مدعی خود مادامی که با وی در راه هستی صلح کن، مبادا مدعی، تو را به قاضی سپارد و قاضی، تو را به داروغه تسلیم کند و در زندان افکنده شوی."},{"v":26,"t":"هرآینه به تو می‌گویم، که تا فلس آخر را ادا نکنی، هرگز از آنجا بیرون نخواهی آمد."},{"v":27,"t":"«شنیده‌اید که به اولین گفته شده است “زنامکن.”"},{"v":28,"t":"لیکن من به شما می‌گویم، هر کس به زنی نظر شهوت اندازد، همان دم در دل خود با او زناکرده است."},{"v":29,"t":"پس اگر چشم راستت تو رابلغزاند، قلعش کن و از خود دور انداز زیرا تو رابهتر آن است که عضوی از اعضایت تباه گردد، ازآنکه تمام بدنت در جهنم افکنده شود."},{"v":30,"t":"و اگردست راستت تو را بلغزاند، قطعش کن و از خوددور انداز، زیرا تو را مفیدتر آن است که عضوی ازاعضای تو نابود شود، از آنکه کل جسدت دردوزخ افکنده شود."},{"v":31,"t":"«و گفته شده است هر‌که از زن خودمفارقت جوید، طلاق نامه‌ای بدو بدهد."},{"v":32,"t":"لیکن من به شما می‌گویم، هر کس بغیر علت زنا، زن خود را از خود جدا کند باعث زنا کردن اومی باشد، و هر‌که زن مطلقه را نکاح کند، زنا کرده باشد."},{"v":33,"t":"«باز شنیده‌اید که به اولین گفته شده است که “قسم دروغ مخور، بلکه قسم های خود را به خداوند وفا کن.”"},{"v":34,"t":"لیکن من به شما می‌گویم، هرگز قسم مخورید، نه به آسمان زیرا که عرش خداست،"},{"v":35,"t":"و نه به زمین زیرا که پای انداز اواست، و نه به ارشلیم زیرا که شهر پادشاه عظیم است،"},{"v":36,"t":"و نه به‌سر خود قسم یاد کن، زیرا که مویی را سفید یا سیاه نمی توانی کرد."},{"v":37,"t":"بلکه سخن شما بلی بلی و نی نی باشد زیرا که زیاده براین از شریر است."},{"v":38,"t":"«شنیده‌اید که گفته شده است.”چشمی به چشمی و دندانی به دندانی “"},{"v":39,"t":"لیکن من به شمامی گویم، با شریر مقاومت مکنید بلکه هر‌که بررخساره راست تو طپانچه زند، دیگری را نیز به سوی او بگردان،"},{"v":40,"t":"و اگر کسی خواهد با تو دعواکند و قبای تو را بگیرد، عبای خود را نیز بدوواگذار،"},{"v":41,"t":"و هرگاه کسی تو را برای یک میل مجبور سازد، دو میل همراه او برو."},{"v":42,"t":"هر کس ازتو سوال کند، بدو ببخش و از کسی‌که قرض از توخواهد، روی خود را مگردان.»"},{"v":43,"t":"«شنیده‌اید که گفته شده است “همسایه خورا محبت نما و با دشمن خود عداوت کن.”"},{"v":44,"t":"امامن به شما می‌گویم که دشمنان خود را محبت نمایید و برای لعن کنندگان خود برکت بطلبید و به آنانی که از شما نفرت کنند، احسان کنید و به هرکه به شما فحش دهد و جفا رساند، دعای خیرکنید،"},{"v":45,"t":"تا پدر خود را که در آسمان است پسران شوید، زیرا که آفتاب خود را بر بدان و نیکان طالع می‌سازد و باران بر عادلان و ظالمان می‌باراند."},{"v":46,"t":"زیرا هرگاه آنانی را محبت نمایید که شما رامحبت می‌نمایند، چه اجر دارید؟ آیا باجگیران چنین نمی کنند؟"},{"v":47,"t":"و هرگاه برادران خود را فقطسلام گویید چه فضیلت دارید؟ آیا باجگیران چنین نمی کنند؟"},{"v":48,"t":"پس شما کامل باشید چنانکه پدر شما که در آسمان است کامل است."}]},"6":{"fa":[{"v":1,"t":"«زنهار عدالت خود را پیش مردم به‌جامیاورید تا شما را ببینند و الا نزد پدر خودکه در آسمان است، اجری ندارید."},{"v":2,"t":"پس چون صدقه دهی، پیش خود کرنا منواز چنانکه ریاکاران در کنایس و بازارها می‌کنند، تا نزد مردم اکرام یابند. هرآینه به شما می‌گویم اجر خود رایافته‌اند."},{"v":3,"t":"بلکه تو چون صدقه دهی، دست چپ تو از آنچه دست راستت می‌کند مطلع نشود،"},{"v":4,"t":"تاصدقه تو در نهان باشد و پدر نهان بین تو، تو راآشکارا اجر خواهد داد."},{"v":5,"t":"«و چون عبادت کنی، مانند ریاکاران مباش زیرا خوش دارند که در کنایس و گوشه های کوچه‌ها ایستاده، نماز گذارند تا مردم ایشان راببینند. هرآینه به شما می‌گویم اجر خود راتحصیل نموده‌اند."},{"v":6,"t":"لیکن تو چون عبادت کنی، به حجره خود داخل شو و در را بسته، پدر خود راکه در نهان است عبادت نما؛ و پدر نهان بین تو، تو را آشکارا جزا خواهد داد."},{"v":7,"t":"و چون عبادت کنید، مانند امت‌ها تکرار باطل مکنید زیرا ایشان گمان می‌برند که به‌سبب زیاد گفتن مستجاب می‌شوند."},{"v":8,"t":"پس مثل ایشان مباشید زیرا که پدر شماحاجات شما را می‌داند پیش از آنکه از او سوال کنید."},{"v":9,"t":"«پس شما به اینطور دعا کنید: “ای پدر ما که در آسمانی، نام تو مقدس باد."},{"v":10,"t":"ملکوت تو بیاید. اراده تو چنانکه در آسمان است، بر زمین نیز کرده شود."},{"v":11,"t":"نان کفاف ما را امروز به ما بده."},{"v":12,"t":"و قرض های ما را ببخش چنانکه ما نیزقرضداران خود را می‌بخشیم."},{"v":13,"t":"و ما را در آزمایش میاور، بلکه از شریر ما رارهایی ده."},{"v":14,"t":"«زیرا هرگاه تقصیرات مردم را بدیشان بیامرزید، پدر آسمانی شما، شما را نیز خواهدآمرزید."},{"v":15,"t":"اما اگر تقصیرهای مردم را نیامرزید، پدر شما هم تقصیرهای شما را نخواهد آمرزید."},{"v":16,"t":"«اما چون روزه‌دارید، مانند ریاکاران ترشرو مباشید زیرا که صورت خویش را تغییرمی دهند تا در نظر مردم روزه‌دار نمایند. هرآینه به شما می‌گویم اجر خود را یافته‌اند."},{"v":17,"t":"لیکن توچون روزه‌داری، سر خود را تدهین کن و روی خود را بشوی"},{"v":18,"t":"تا در نظر مردم روزه‌دار ننمایی، بلکه در حضور پدرت که در نهان است؛ و پدر نهان بین تو، تو را آشکارا جزا خواهد داد."},{"v":19,"t":"«گنجها برای خود بر زمین نیندوزید، جایی که بید و زنگ زیان می‌رساند و جایی که دزدان نقب می‌زنند و دزدی می‌نمایند."},{"v":20,"t":"بلکه گنجهابجهت خود در آسمان بیندوزید، جایی که بید وزنگ زیان نمی رساند و جایی که دزدان نقب نمی زنند و دزدی نمی کنند."},{"v":21,"t":"زیرا هرجا گنج تواست دل تو نیز در آنجا خواهد بود."},{"v":22,"t":"«چراغ بدن چشم است؛ پس هرگاه چشمت بسیط باشد تمام بدنت روشن بود؛"},{"v":23,"t":"امااگر چشم تو فاسد است، تمام جسدت تاریک می‌باشد. پس اگر نوری که در تو است ظلمت باشد، چه ظلمت عظیمی است!"},{"v":24,"t":"«هیچ‌کس دو آقا را خدمت نمی تواند کرد، زیرا یا از یکی نفرت دارد و با دیگری محبت، و یابه یکی می‌چسبد و دیگر را حقیر می‌شمارد. محال است که خدا و ممونا را خدمت کنید."},{"v":25,"t":"«بنابراین به شما می‌گویم، از بهر جان خوداندیشه مکنید که چه خورید یا چه آشامید و نه برای بدن خود که چه بپوشید. آیا جان، از خوراک و بدن از پوشاک بهتر نیست؟"},{"v":26,"t":"مرغان هوا را نظرکنید که نه می‌کارند و نه می‌دروند و نه در انبارهاذخیره می‌کنند و پدر آسمانی شما آنها رامی پروراند. آیا شما از آنها بمراتب بهتر نیستید؟"},{"v":27,"t":"و کیست از شما که به تفکر بتواند ذراعی برقامت خود افزاید؟"},{"v":28,"t":"و برای لباس چرا می اندیشید؟ در سوسنهای چمن تامل کنید، چگونه نمو می‌کنند! نه محنت می‌کشند و نه می‌ریسند!"},{"v":29,"t":"لیکن به شما می‌گویم سلیمان هم باهمه جلال خود چون یکی از آنها آراسته نشد."},{"v":30,"t":"پس اگر خدا علف صحرا را که امروز هست وفردا در تنور افکنده می‌شود چنین بپوشاند، ای کم‌ایمانان آیا نه شما را از طریق اولی؟"},{"v":31,"t":"پس اندیشه مکنید و مگویید چه بخوریم یا چه بنوشیم یا چه بپوشیم."},{"v":32,"t":"زیرا که در طلب جمیع این چیزها امت‌ها می‌باشند. اما پدر آسمانی شمامی داند که بدین همه‌چیز احتیاج دارید."},{"v":33,"t":"لیکن اول ملکوت خدا و عدالت او را بطلبید که این همه برای شما مزید خواهد شد."},{"v":34,"t":"پس در اندیشه فردا مباشید زیرا فردا اندیشه خود را خواهد کرد. بدی امروز برای امروز کافی است."}]},"7":{"fa":[{"v":1,"t":"«حکم مکنید تا بر شما حکم نشود."},{"v":2,"t":"زیرابدان طریقی که حکم کنید بر شما نیز حکم خواهد شد و بدان پیمانه‌ای که پیمایید برای شماخواهند پیمود."},{"v":3,"t":"و چون است که خس را درچشم برادر خود می‌بینی و چوبی را که چشم خود داری نمی یابی؟"},{"v":4,"t":"یا چگونه به برادر خودمی گویی “اجازت ده تا خس را از چشمت بیرون کنم “ و اینک چوب در چشم تو است؟"},{"v":5,"t":"‌ای ریاکار، اول چوب را از چشم خود بیرون کن، آنگاه نیک خواهی دید تا خس را از چشم برادرت بیرون کنی!"},{"v":6,"t":"«آنچه مقدس است، به سگان مدهید و نه مرواریدهای خود را پیش گرازان اندازید، مباداآنها را پایمال کنند و برگشته، شما را بدرند."},{"v":7,"t":"«سوال کنید که به شما داده خواهد شد؛ بطلبید که خواهید یافت؛ بکوبید که برای شما بازکرده خواهد شد."},{"v":8,"t":"زیرا هر‌که سوال کند، یابد وکسی‌که بطلبد دریافت کند و هر‌که بکوبد برای اوگشاده خواهد شد."},{"v":9,"t":"و کدام آدمی است از شما که پسرش نانی از او خواهد و سنگی بدو دهد؟"},{"v":10,"t":"یااگر ماهی خواهد ماری بدو بخشد؟"},{"v":11,"t":"پس هرگاه شما که شریر هستید، دادن بخشش های نیکو را به اولاد خود می‌دانید، چقدر زیاده پدر شما که درآسمان است چیزهای نیکو را به آنانی که از اوسوال می‌کنند خواهد بخشید!"},{"v":12,"t":"لهذا آنچه خواهید که مردم به شما کنند، شما نیز بدیشان همچنان کنید، زیرا این است تورات و صحف انبیا."},{"v":13,"t":"«از در تنگ داخل شوید. زیرا فراخ است آن در و وسیع است آن طریقی که مودی به هلاکت است و آنانی که بدان داخل می‌شوندبسیارند."},{"v":14,"t":"زیرا تنگ است آن در و دشوار است آن طریقی که مودی به حیات‌است و یابندگان آن کمند."},{"v":15,"t":"«اما از انبیای کذبه احتراز کنید، که به لباس میشها نزد شما می‌آیند ولی در باطن، گرگان درنده می‌باشند."},{"v":16,"t":"ایشان را از میوه های ایشان خواهید شناخت. آیا انگور را از خار و انجیر را ازخس می‌چینند؟"},{"v":17,"t":"همچنین هر درخت نیکو، میوه نیکو می‌آورد و درخت بد، میوه بد می‌آورد."},{"v":18,"t":"نمی تواند درخت خوب میوه بد آورد، و نه درخت بد میوه نیکو آورد."},{"v":19,"t":"هر درختی که میوه نیکو نیاورد، بریده و در آتش افکنده شود."},{"v":20,"t":"لهذا از میوه های ایشان، ایشان را خواهیدشناخت."},{"v":21,"t":"«نه هر‌که مرا “خداوند، خداوند” گویدداخل ملکوت آسمان گردد، بلکه آنکه اراده پدرمرا که در آسمان است به‌جا آورد."},{"v":22,"t":"بسا در آن روز مرا خواهند گفت: “خداوندا، خداوندا، آیا به نام تو نبوت ننمودیم و به اسم تو دیوها را اخراج نکردیم و به نام تو معجزات بسیار ظاهرنساختیم؟”"},{"v":23,"t":"آنگاه به ایشان صریح خواهم گفت که “هرگز شما را نشناختم! ای بدکاران از من دور شوید!”"},{"v":24,"t":"«پس هر‌که این سخنان مرا بشنود و آنها رابه‌جا آرد، او را به مردی دانا تشبیه می‌کنم که خانه خود را بر سنگ بنا کرد."},{"v":25,"t":"و باران باریده، سیلابهاروان گردید و بادها وزیده، بدان خانه زورآور شدو خراب نگردید زیرا که بر سنگ بنا شده بود."},{"v":26,"t":"وهر‌که این سخنان مرا شنیده، به آنها عمل نکرد، به مردی نادان ماند که خانه خود را بر ریگ بنا نهاد."},{"v":27,"t":"و باران باریده، سیلابها جاری شد و بادهاوزیده، بدان خانه زور آورد و خراب گردید وخرابی آن عظیم بود.»"},{"v":28,"t":"و چون عیسی این سخنان را ختم کرد آن گروه از تعلیم او در حیرت افتادند،"},{"v":29,"t":"زیرا که ایشان را چون صاحب قدرت تعلیم می‌داد و نه مثل کاتبان."}]},"8":{"fa":[{"v":1,"t":"و چون او از کوه به زیر آمد، گروهی بسیاراز عقب او روانه شدند."},{"v":2,"t":"که ناگاه ابرصی آمد و او را پرستش نموده، گفت: «ای خداوند اگربخواهی، می‌توانی مرا طاهر سازی.»"},{"v":3,"t":"عیسی دست آورده، او را لمس نمود و گفت: «می‌خواهم؛ طاهر شو!» که فور برص او طاهرگشت."},{"v":4,"t":"عیسی بدو گفت: «زنهار کسی را اطلاع ندهی بلکه رفته، خود را به کاهن بنما و آن هدیه‌ای را که موسی فرمود، بگذران تا بجهت ایشان شهادتی باشد.»"},{"v":5,"t":"و چون عیسی وارد کفرناحوم شد، یوزباشی‌ای نزد وی آمد و بدو التماس نموده،"},{"v":6,"t":"گفت: «ای خداوند، خادم من مفلوج در خانه خوابیده و بشدت متالم است.»"},{"v":7,"t":"عیسی بدو گفت: «من آمده، او را شفا خواهم داد.»"},{"v":8,"t":"یوزباشی در جواب گفت: «خداوندا، لایق آن نی‌ام که زیرسقف من آیی. بلکه فقط سخنی بگو و خادم من صحت خواهد یافت."},{"v":9,"t":"زیرا که من نیز مردی زیرحکم هستم و سپاهیان را زیر دست خود دارم؛ چون به یکی گویم برو، می‌رود و به دیگری بیا، می‌آید و به غلام خود فلان کار را بکن، می‌کند.»"},{"v":10,"t":"عیسی چون این سخن را شنید، متعجب شده، به همراهان خود گفت: «هرآینه به شما می‌گویم که چنین ایمانی در اسرائیل هم نیافته‌ام."},{"v":11,"t":"و به شما می‌گویم که بسا از مشرق و مغرب آمده، درملکوت آسمان با ابراهیم و اسحاق و یعقوب خواهند نشست؛"},{"v":12,"t":"اما پسران ملکوت بیرون افکنده خواهند شد، در ظلمت خارجی جایی که گریه و فشار دندان باشد."},{"v":13,"t":"پس عیسی به یوزباشی گفت: «برو، بر وفق ایمانت تو را عطاشود، » که در ساعت خادم او صحت یافت."},{"v":14,"t":"و چون عیسی به خانه پطرس آمد، مادر‌زن او را دید که تب کرده، خوابیده است."},{"v":15,"t":"پس دست او را لمس کرد و تب او را رها کرد. پس برخاسته، به خدمت گذاری ایشان مشغول گشت."},{"v":16,"t":"اما چون شام شد، بسیاری از دیوانگان را به نزداو آوردند و محض سخنی ارواح را بیرون کرد وهمه مریضان را شفا بخشید."},{"v":17,"t":"تا سخنی که به زبان اشعیای نبی گفته شده بود تمام گردد که «او ضعف های ما را گرفت و مرض های ما رابرداشت.»"},{"v":18,"t":"چون عیسی جمعی کثیر دور خود دید، فرمان داد تا به کناره دیگر روند."},{"v":19,"t":"آنگاه کاتبی پیش آمده، بدو گفت: «استادا هرجا روی، تو رامتابعت کنم.»"},{"v":20,"t":"عیسی بدو گفت: «روباهان راسوراخها و مرغان هوا را آشیانه‌ها است. لیکن پسر انسان را جای سر نهادن نیست.»"},{"v":21,"t":"و دیگری از شاگردانش بدو گفت: «خداوندا اول مرارخصت ده تا رفته، پدر خود را دفن کنم.»"},{"v":22,"t":"عیسی وی را گفت: «مرا متابعت کن و بگذار که مردگان، مردگان خود را دفن کنند.»"},{"v":23,"t":"چون به کشتی سوار شد، شاگردانش ازعقب او آمدند."},{"v":24,"t":"ناگاه اضطراب عظیمی در دریاپدید آمد، بحدی که امواج، کشتی را فرومی گرفت؛ و او در خواب بود."},{"v":25,"t":"پس شاگردان پیش آمده، او را بیدار کرده، گفتند: «خداوندا، مارا دریاب که هلاک می‌شویم!»"},{"v":26,"t":"بدیشان گفت: «ای کم‌ایمانان، چرا ترسان هستید؟» آنگاه برخاسته، بادها و دریا را نهیب کرد که آرامی کامل پدید آمد."},{"v":27,"t":"اما آن اشخاص تعجب نموده، گفتند: «این چگونه مردی است که بادها و دریا نیزاو را اطاعت می‌کنند!»"},{"v":28,"t":"و چون به آن کناره در زمین جرجسیان رسید، دو شخص دیوانه از قبرها بیرون شده، بدوبرخوردند و بحدی تندخوی بودند که هیچ‌کس از آن راه نتوانستی عبور کند."},{"v":29,"t":"در ساعت فریادکرده، گفتند: «یا عیسی ابن‌الله، ما را با تو جه کار است؟ مگر در اینجا آمده‌ای تا ما را قبل از وقت عذاب کنی؟”"},{"v":30,"t":"و گلۀگراز بسیاری دور از ایشان می‌چرید."},{"v":31,"t":"دیوها از وی استدعا نموده، گفتند: “هرگاه ما را بیرون کنی، در گلۀ گرازان ما را بفرست.”"},{"v":32,"t":"ایشان را گفت: “بروید!” در حال بیرون شده، داخل گلۀ گرازان گردیدند که فی‌الفور همۀ آن گرازان از بلندی به دریا جسته، در آب هلاک شدند."},{"v":33,"t":"اما شبانان گریخته، به شهر رفتند و تمام آن حادثه و ماجرای دیوانگان را شهرت دادند."},{"v":34,"t":"واینک تمام شهر برای ملاقات عیسی بیرون آمد. چون او را دیدند، التماس نمودند که از حدودایشان بیرون رود."}]},"9":{"fa":[{"v":1,"t":"پس به کشتی سوار شده، عبور کرد و به شهر خویش آمد."},{"v":2,"t":"ناگاه مفلوجی را بر بستر خوابانیده، نزد وی آوردند. چون عیسی ایمان ایشان را دید، مفلوج را گفت: «ای فرزند، خاطر جمع دار که گناهانت آمرزیده شد.»"},{"v":3,"t":"آنگاه بعضی از کاتبان با خود گفتند: «این شخص کفر می‌گوید.»"},{"v":4,"t":"عیسی خیالات ایشان رادرک نموده، گفت: «از بهر‌چه خیالات فاسد به‌خاطر خود راه می‌دهید؟"},{"v":5,"t":"زیرا کدام سهل تراست، گفتن اینکه گناهان تو آمرزیده شد یا گفتن آنکه برخاسته بخرام؟"},{"v":6,"t":"لیکن تا بدانید که پسرانسان را قدرت آمرزیدن گناهان بر روی زمین هست...» آنگاه مفلوج را گفت: «برخیز و بسترخود را برداشته، به خانه خود روانه شو!»"},{"v":7,"t":"درحال برخاسته، به خانه خود رفت!"},{"v":8,"t":"و آن گروه چون این عمل را دیدند، متعجب شده، خدایی راکه این نوع قدرت به مردم عطا فرموده بود، تمجیدنمودند."},{"v":9,"t":"چون عیسی از آنجا می‌گذشت، مردی رامسمی به متی به باج گاه نشسته دید. بدو گفت: «مرا متابعت کن.» در حال برخاسته، از عقب وی روانه شد."},{"v":10,"t":"و واقع شد چون او در خانه به غذا نشسته بود که جمعی از باجگیران وگناهکاران آمده، با عیسی و شاگردانش بنشستند."},{"v":11,"t":"«و فریسیان چون دیدند، به شاگردان اوگفتند: «چرا استاد شما با باجگیران وگناهکاران غذا می‌خورد؟»"},{"v":12,"t":"عیسی چون شنید، گفت: «نه تندرستان بلکه مریضان احتیاج به طبیب دارند."},{"v":13,"t":"لکن رفته، این را دریافت کنید که “رحمت می‌خواهم نه قربانی “، زیرا نیامده‌ام تاعادلان را بلکه گناهکاران را به توبه دعوت نمایم.»"},{"v":14,"t":"آنگاه شاگردان یحیی نزد وی آمده، گفتند: «چون است که ما و فریسیان روزه بسیارمی داریم، لکن شاگردان تو روزه نمی دارند؟»"},{"v":15,"t":"عیسی بدیشان گفت: «آیا پسران خانه عروسی، مادامی که داماد با ایشان است، می‌توانند ماتم کنند؟ و لکن ایامی می‌آید که داماد از ایشان گرفته شود؛ در آن هنگام روزه خواهند داشت."},{"v":16,"t":"وهیچ‌کس بر جامه کهنه پاره‌ای از پارچه نو وصله نمی کند زیرا که آن وصله از جامه جدا می‌گردد ودریدگی بدتر می‌شود."},{"v":17,"t":"و شراب نو را درمشکهای کهنه نمی ریزند والا مشکها دریده شده، شراب ریخته و مشکها تباه گردد. بلکه شراب نو را در مشکهای نو می‌ریزند تا هر دومحفوظ باشد.»"},{"v":18,"t":"او هنوز این سخنان را بدیشان می‌گفت که ناگاه رئیسی آمد و او را پرستش نموده، گفت: «اکنون دختر من مرده است. لکن بیا و دست خودرا بر وی گذار که زیست خواهد کرد.»"},{"v":19,"t":"پس عیسی به اتفاق شاگردان خود برخاسته، از عقب او روان شد."},{"v":20,"t":"و اینک زنی که مدت دوازده سال به مرض استحاضه مبتلا می‌بود، از عقب او آمده، دامن ردای او را لمس نمود،"},{"v":21,"t":"زیرا با خود گفته بود: «اگر محض ردایش را لمس کنم، هرآینه شفایابم.»"},{"v":22,"t":"عیسی برگشته، نظر بر وی انداخته، گفت: «ای دختر، خاطرجمع باش زیرا که ایمانت تو را شفا داده است!» در ساعت آن زن رستگارگردید."},{"v":23,"t":"و چون عیسی به خانه رئیس در‌آمد، نوحه‌گران و گروهی از شورش کنندگان را دیده،"},{"v":24,"t":"بدیشان گفت: «راه دهید، زیرا دختر نمرده بلکه در خواب است.» ایشان بر وی سخریه کردند."},{"v":25,"t":"اما چون آن گروه بیرون شدند، داخل شده، دست آن دختر را گرفت که در ساعت برخاست."},{"v":26,"t":"و این کار در تمام آن مرز وبوم شهرت یافت."},{"v":27,"t":"و چون عیسی از آن مکان می‌رفت، دو کورفریاد‌کنان در عقب او افتاده، گفتند: «پسر داودا، بر ما ترحم کن!»"},{"v":28,"t":"و چون به خانه در‌آمد، آن دوکور نزد او آمدند. عیسی بدیشان گفت: «آیا ایمان دارید که این کار را می‌توانم کرد؟» گفتندش: «بلی خداوندا.»"},{"v":29,"t":"در ساعت چشمان ایشان را لمس کرده، گفت: «بر وفق ایمانتان به شما بشود.»"},{"v":30,"t":"درحال چشمانشان باز شد و عیسی ایشان را به تاکیدفرمود که «زنهار کسی اطلاع نیابد.»"},{"v":31,"t":"اما ایشان بیرون رفته، او را در تمام آن نواحی شهرت دادند."},{"v":32,"t":"و هنگامی که ایشان بیرون می‌رفتند، ناگاه دیوانه‌ای گنگ را نزد او آوردند."},{"v":33,"t":"و چون دیوبیرون شد، گنگ، گویا گردید و همه در تعجب شده، گفتند: «در اسرائیل چنین امر هرگز دیده نشده بود.»"},{"v":34,"t":"لیکن فریسیان گفتند: «به واسطه رئیس دیوها، دیوها را بیرون می‌کند.»"},{"v":35,"t":"و عیسی در همه شهرها و دهات گشته، در کنایس ایشان تعلیم داده، به بشارت ملکوت موعظه می‌نمود و هر مرض و رنج مردم را شفامی داد."},{"v":36,"t":"و چون جمع کثیر دید، دلش بر ایشان بسوخت زیرا که مانند گوسفندان بی‌شبان، پریشان حال و پراکنده بودند."},{"v":37,"t":"آنگاه به شاگردان خود گفت: «حصاد فراوان است لیکن عمله کم. پس از صاحب حصاد استدعا نمایید تاعمله در حصاد خود بفرستد.»"}]},"10":{"fa":[{"v":1,"t":"و دوازده شاگرد خود را طلبیده، ایشان را بر ارواح پلید قدرت داد که آنها رابیرون کنند و هر بیماری و رنجی را شفا دهند."},{"v":2,"t":"ونامهای دوازده رسول این است: اول شمعون معروف به پطرس و برادرش اندریاس؛ یعقوب بن زبدی و برادرش یوحنا؛"},{"v":3,"t":"فیلپس و برتولما؛ توماو متای باجگیر؛ یعقوب بن حلفی و لبی معروف به تدی؛"},{"v":4,"t":"شمعون قانوی و یهودای اسخریوطی که او را تسلیم نمود."},{"v":5,"t":"این دوازده را عیسی فرستاده، بدیشان وصیت کرده، گفت: «از راه امت‌ها مروید و دربلدی از سامریان داخل مشوید،"},{"v":6,"t":"بلکه نزدگوسفندان گم شده اسرائیل بروید."},{"v":7,"t":"و چون می‌روید، موعظه کرده، گویید که ملکوت آسمان نزدیک است."},{"v":8,"t":"بیماران را شفا دهید، ابرصان راطاهر سازید، مردگان را زنده کنید، دیوها را بیرون نمایید. مفت یافته‌اید، مفت بدهید."},{"v":9,"t":"طلا یا نقره یا مس در کمرهای خود ذخیره مکنید،"},{"v":10,"t":"و برای سفر، توشه‌دان یا دو پیراهن یا کفشها یا عصابرندارید، زیرا که مزدور مستحق خوراک خوداست."},{"v":11,"t":"و در هر شهری یا قریه‌ای که داخل شوید، بپرسید که در آنجا که لیاقت دارد؛ پس درآنجا بمانید تا بیرون روید."},{"v":12,"t":"و چون به خانه‌ای درآیید، بر آن سلام نمایید؛"},{"v":13,"t":"پس اگر خانه لایق باشد، سلام شما بر آن واقع خواهد شد و اگرنالایق بود، سلام شما به شما خواهد برگشت."},{"v":14,"t":"و هر‌که شما را قبول نکند یا به سخن شماگوش ندهد، از آن خانه یا شهر بیرون شده، خاک پایهای خود را برافشانید."},{"v":15,"t":"هرآینه به شمامی گویم که در روز جزا حالت زمین سدوم وغموره از آن شهر سهل تر خواهد بود."},{"v":16,"t":"هان، من شما را مانند گوسفندان در میان گرگان می‌فرستم؛ پس مثل مارها هوشیار و چون کبوتران ساده باشید."},{"v":17,"t":"اما از مردم برحذر باشید، زیرا که شما را به مجلسها تسلیم خواهند کرد ودر کنایس خود شما را تازیانه خواهند زد،"},{"v":18,"t":"ودر حضور حکام و سلاطین، شما را بخاطر من خواهند برد تا بر ایشان و بر امت‌ها شهادتی شود."},{"v":19,"t":"اما چون شما را تسلیم کنند، اندیشه مکنید که چگونه یا چه بگویید زیرا در همان ساعت به شماعطا خواهد شد که چه باید گفت،"},{"v":20,"t":"زیرا گوینده شما نیستید بلکه روح پدر شما، در شما گوینده است."},{"v":21,"t":"و برادر، برادر را و پدر، فرزند را به موت تسلیم خواهند کرد و فرزندان بر والدین خودبرخاسته، ایشان را به قتل خواهند رسانید؛"},{"v":22,"t":"و به جهت اسم من، جمیع مردم از شما نفرت خواهندکرد. لیکن هر‌که تا به آخر صبر کند، نجات یابد."},{"v":23,"t":"و وقتی که در یک شهر بر شما جفا کنند، به دیگری فرار کنید زیرا هرآینه به شما می‌گویم تاپسر انسان نیاید، از همه شهرهای اسرائیل نخواهید پرداخت."},{"v":24,"t":"شاگرد از معلم خود افضل نیست و نه غلام از آقایش برتر."},{"v":25,"t":"کافی است شاگرد را که چون استاد خویش گردد و غلام را که چون آقای خودشود. پس اگر صاحب‌خانه را بعلزبول خواندند، چقدر زیادتر اهل خانه‌اش را."},{"v":26,"t":"لهذا از ایشان مترسید زیرا چیزی مستور نیست که مکشوف نگردد و نه مجهولی که معلوم نشود."},{"v":27,"t":"آنچه درتاریکی به شما می‌گویم، در روشنایی بگویید، وآنچه در گوش شنوید بر بامها موعظه کنید."},{"v":28,"t":"واز قاتلان جسم که قادر بر کشتن روح نی‌اند، بیم مکنید بلکه از او بترسید که قادر است بر هلاک کردن روح و جسم را نیز در جهنم."},{"v":29,"t":"آیا دوگنجشک به یک فلس فروخته نمی شود؟ و حال آنکه یکی از آنها جز به حکم پدر شما به زمین نمی افتد."},{"v":30,"t":"لیکن همه مویهای سر شما نیزشمرده شده است."},{"v":31,"t":"پس ترسان مباشید زیراشما از گنجشکان بسیار افضل هستید."},{"v":32,"t":"پس هر‌که مرا پیش مردم اقرار کند، من نیزدر حضور پدر خود که در آسمان است، او رااقرار خواهم کرد."},{"v":33,"t":"اما هر‌که مرا پیش مردم انکار نماید، من هم در حضور پدر خود که در آسمان است او را انکار خواهم نمود."},{"v":34,"t":"گمان مبرید که آمده‌ام تا سلامتی بر زمین بگذارم. نیامده‌ام تا سلامتی بگذارم بلکه شمشیر را."},{"v":35,"t":"زیرا که آمده‌ام تا مرد را از پدر خود و دختر رااز مادر خویش و عروس را از مادر شوهرش جداسازم."},{"v":36,"t":"و دشمنان شخص، اهل خانه او خواهندبود."},{"v":37,"t":"و هر‌که پدر یا مادر را بیش از من دوست دارد؛ لایق من نباشد و هر‌که پسر یا دختر را از من زیاده دوست دارد، لایق من نباشد."},{"v":38,"t":"و هر‌که صلیب خود را برنداشته، از عقب من نیاید، لایق من نباشد."},{"v":39,"t":"هر‌که جان خود را دریابد، آن راهلاک سازد و هر‌که جان خود را بخاطر من هلاک کرد، آن را خواهد دریافت."},{"v":40,"t":"هر‌که شما را قبول کند، مرا قبول کرده و کسی‌که مرا قبول کرده، فرستنده مرا قبول کرده باشد."},{"v":41,"t":"و آنکه نبی‌ای رابه اسم نبی پذیرد، اجرت نبی یابد و هر‌که عادلی را به اسم عادلی پذیرفت، مزد عادل را خواهدیافت."},{"v":42,"t":"و هر‌که یکی از این صغار را کاسه‌ای ازآب سرد محض نام شاگرد نوشاند، هرآینه به شمامی گویم اجر خودرا ضایع نخواهد ساخت.»"}]},"11":{"fa":[{"v":1,"t":"و چون عیسی این وصیت را با دوازده شاگرد خود به اتمام رسانید، از آنجا روانه شد تا در شهرهای ایشان تعلیم دهد و موعظه نماید."},{"v":2,"t":"و چون یحیی در زندان، اعمال مسیح راشنید، دو نفر از شاگردان خود را فرستاده،"},{"v":3,"t":"بدو گفت: «آیا آن آینده تویی یا منتظر دیگری باشیم؟»"},{"v":4,"t":"عیسی در جواب ایشان گفت: «بروید ویحیی را از آنچه شنیده و دیده‌اید، اطلاع دهید"},{"v":5,"t":"که کوران بینا می‌گردند و لنگان به رفتار می‌آیندو ابرصان طاهر و کران شنوا و مردگان زنده می‌شوند و فقیران بشارت می‌شنوند؛"},{"v":6,"t":"وخوشابحال کسی‌که در من نلغزد.»"},{"v":7,"t":"و چون ایشان می‌رفتند، عیسی با آن جماعت درباره یحیی آغاز سخن کرد که «بجهت دیدن چه چیز بیرون شدید؟ آیا نی را که از باد درجنبش است؟"},{"v":8,"t":"بلکه بجهت دیدن چه چیز بیرون شدید؟ آیا مردی را که لباس فاخر در بر دارد؟ اینک آنانی که رخت فاخر می‌پوشند در خانه های پادشاهان می‌باشند."},{"v":9,"t":"لیکن بجهت دیدن چه چیزبیرون رفتید؟ آیا نبی را؟ بلی به شما می‌گویم ازنبی افضلی را!"},{"v":10,"t":"زیرا همان است آنکه درباره اومکتوب است: “اینک من رسول خود را پیش روی تو می‌فرستم تا راه تو را پیش روی تو مهیا سازد.”"},{"v":11,"t":"هرآینه به شما می‌گویم که از اولاد زنان، بزرگتری از یحیی تعمید‌دهنده برنخاست، لیکن کوچکتر در ملکوت آسمان از وی بزرگ تر است."},{"v":12,"t":"و از ایام یحیی تعمید‌دهنده تا الان، ملکوت آسمان محبور می‌شود و جباران آن را به زورمی ربایند."},{"v":13,"t":"زیرا جمیع انبیا و تورات تا یحیی اخبار می‌نمودند."},{"v":14,"t":"و اگر خواهید قبول کنید، همان است الیاس که باید بیاید."},{"v":15,"t":"هر‌که گوش شنوا دارد بشنود."},{"v":16,"t":"لیکن این طایفه را به چه چیزتشبیه نمایم؟ اطفالی را مانند که در کوچه هانشسته، رفیقان خویش را صدا زده،"},{"v":17,"t":"می‌گویند: “برای شما نی نواختیم، رقص نکردید؛ نوحه گری کردیم، سینه نزدید.”"},{"v":18,"t":"زیرا که یحیی آمد، نه می‌خورد و نه می‌آشامید، می‌گویند دیو دارد."},{"v":19,"t":"پسر انسان آمد که می‌خورد و می‌نوشد، می‌گویند اینک مردی پرخور و میگسار و دوست باجگیران و گناهکاران است. لیکن حکمت ازفرزندان خود تصدیق کرده شده است.”» وعده آرامش درون"},{"v":20,"t":"آنگاه شروع به ملامت نمود بر آن شهرهایی که اکثر از معجزات وی در آنها ظاهرشد زیرا که توبه نکرده بودند:"},{"v":21,"t":"«وای بر تو‌ای خورزین! وای بر تو‌ای بیت صیدا! زیرا اگرمعجزاتی که در شما ظاهر گشت، در صور وصیدون ظاهر می‌شد، هرآینه مدتی در پلاس وخاکستر توبه می‌نمودند."},{"v":22,"t":"لیکن به شما می‌گویم که در روز جزا حالت صور و صیدون از شماسهلتر خواهد بود."},{"v":23,"t":"و تو‌ای کفرناحوم که تا به فلک سرافراشته‌ای، به جهنم سرنگون خواهی شد زیرا هرگاه معجزاتی که در تو پدید آمد درسدوم ظاهر می‌شد، هرآینه تا امروز باقی می‌ماند."},{"v":24,"t":"لیکن به شما می‌گویم که در روز جزاحالت زمین سدوم از تو سهل تر خواهد بود.»"},{"v":25,"t":"در آن وقت، عیسی توجه نموده، گفت: «ای پدر، مالک آسمان و زمین، تو را ستایش می‌کنم که این امور را از دانایان و خردمندان پنهان داشتی و به کودکان مکشوف فرمودی!"},{"v":26,"t":"بلی‌ای پدر، زیرا که همچنین منظور نظر تو بود."},{"v":27,"t":"پدر همه‌چیز را به من سپرده است و کسی پسر را نمی شناسد بجز پدر و نه پدر را هیچ‌کس می‌شناسد غیر از پسر و کسی‌که پسر بخواهد بدومکشوف سازد."},{"v":28,"t":"بیاید نزد من‌ای تمام زحمتکشان و گرانباران و من شما را آرامی خواهم بخشید."},{"v":29,"t":"یوغ مرا بر خود گیرید و از من تعلیم یابید زیرا که حلیم و افتاده‌دل می‌باشم و درنفوس خود آرامی خواهید یافت؛"},{"v":30,"t":"زیرا یوغ من خفیف است و بار من سبک.»"}]},"12":{"fa":[{"v":1,"t":"در آن زمان، عیسی در روز سبت از میان کشتزارها می‌گذشت و شاگردانش چون گرسنه بودند، به چیدن و خوردن خوشه هاآغاز کردند."},{"v":2,"t":"اما فریسیان چون این را دیدند، بدوگفتند: «اینک شاگردان تو عملی می‌کنند که کردن آن در سبت جایز نیست.»"},{"v":3,"t":"ایشان را گفت: «مگرنخوانده‌اید آنچه داود و رفیقانش کردند، وقتی که گرسنه بودند؟"},{"v":4,"t":"چه طور به خانه خدا در‌آمده، نانهای تقدمه را خورد که خوردن آن بر او ورفیقانش حلال نبود بلکه بر کاهنان فقط."},{"v":5,"t":"یا درتورات نخوانده‌اید که در روزهای سبت، کهنه درهیکل سبت را حرمت نمی دارند و بی‌گناه هستند؟"},{"v":6,"t":"لیکن به شما می‌گویم که در اینجاشخصی بزرگتر از هیکل است!"},{"v":7,"t":"و اگر این معنی را درک می‌کردید که رحمت می‌خواهم نه قربانی، بی‌گناهان را مذمت نمی نمودید."},{"v":8,"t":"زیرا که پسرانسان مالک روز سبت نیز ا§ست.»"},{"v":9,"t":"و از آنجا رفته، به کنیسه ایشان درآمد،"},{"v":10,"t":"که ناگاه شخص دست خشکی حاضر بود. پس ازوی پرسیده، گفتند: «آیا در روز سبت شفا دادن جایز است یا نه؟» تا ادعایی بر او وارد آورند."},{"v":11,"t":"وی به ایشان گفت: «کیست از شما که یک گوسفند داشته باشد و هرگاه آن در روز سبت به حفره‌ای افتد، او را نخواهد گرفت و بیرون آورد؟"},{"v":12,"t":"پس چقدر انسان از گوسفند افضل است. بنابراین در سبت‌ها نیکویی‌کردن روا است.»"},{"v":13,"t":"آنگاه آن مرد را گفت: «دست خود را دراز کن!» پس دراز کرده، مانند دیگری صحیح گردید."},{"v":14,"t":"اما فریسیان بیرون رفته، بر او شورا نمودند که چطور او را هلاک کنند."},{"v":15,"t":"عیسی این را درک نموده، از آنجا روانه شدو گروهی بسیار از عقب او آمدند. پس جمیع ایشان را شفا بخشید،"},{"v":16,"t":"و ایشان را قدغن فرمودکه او را شهرت ندهند."},{"v":17,"t":"تا تمام گردد کلامی که به زبان اشعیای نبی گفته شده بود:"},{"v":18,"t":"«اینک بنده من که او را برگزیدم و حبیب من که خاطرم از وی خرسند است. روح خود را بر وی خواهم نهاد تاانصاف را بر امت‌ها اشتهار نماید."},{"v":19,"t":"نزاع و فغان نخواهد کرد و کسی آواز او را در کوچه هانخواهد شنید."},{"v":20,"t":"نی خرد شده را نخواهد شکست و فتیله نیم‌سوخته را خاموش نخواهدکرد تا آنکه انصاف را به نصرت برآورد."},{"v":21,"t":"و به نام او امت‌ها امید خواهند داشت.»"},{"v":22,"t":"آنگاه دیوانه‌ای کور و گنگ را نزد او آوردندو او را شفا داد چنانکه آن کور و گنگ، گویا و بیناشد."},{"v":23,"t":"و تمام آن گروه در حیرت افتاده، گفتند: «آیا این شخص پسر داود نیست؟»"},{"v":24,"t":"لیکن فریسیان شنیده، گفتند: «این شخص دیوها رابیرون نمی کند مگر به یاری بعلزبول، رئیس دیوها!»"},{"v":25,"t":"عیسی خیالات ایشان را درک نموده، بدیشان گفت: «هر مملکتی که بر خود منقسم گردد، ویران شود و هر شهری یا خانه‌ای که برخود منقسم گردد، برقرار نماند."},{"v":26,"t":"لهذا اگرشیطان، شیطان را بیرون کند، هرآینه بخلاف خودمنقسم گردد. پس چگونه سلطنتش پایدار ماند؟"},{"v":27,"t":"و اگر من به وساطت بعلزبول دیوها را بیرون می‌کنم، پسران شما آنها را به یاری که بیرون می‌کنند؟ از این جهت ایشان بر شما داوری خواهند کرد."},{"v":28,"t":"لیکن هرگاه من به روح خدادیوها را اخراج می‌کنم، هرآینه ملکوت خدا برشما رسیده است."},{"v":29,"t":"و چگونه کسی بتواند درخانه شخصی زورآور درآید و اسباب او را غارت کند، مگر آنکه اول آن زورآور را ببندد و پس خانه او را تاراج کند؟"},{"v":30,"t":"هر‌که با من نیست، برخلاف من است و هر‌که با من جمع نکند، پراکنده سازد."},{"v":31,"t":"از این‌رو، شما را می‌گویم هر نوع گناه و کفر از انسان آمرزیده می‌شود، لیکن کفر به روح‌القدس از انسان عفو نخواهد شد."},{"v":32,"t":"وهرکه برخلاف پسر انسان سخنی گوید، آمرزیده شود اما کسی‌که برخلاف روح‌القدس گوید، دراین عالم و در عالم آینده، هرگز آمرزیده نخواهدشد."},{"v":33,"t":"یا درخت را نیکو گردانید و میوه‌اش رانیکو، یا درخت را فاسد سازید و میوه‌اش رافاسد، زیرا که درخت از میوه‌اش شناخته می‌شود."},{"v":34,"t":"‌ای افعی‌زادگان، چگونه می‌توانیدسخن نیکو گفت و حال آنکه بد هستید زیرا که زبان از زیادتی دل سخن می‌گوید."},{"v":35,"t":"مرد نیکو ازخزانه نیکوی دل خود، چیزهای خوب برمی آورد و مرد بد از خزانه بد، چیزهای بدبیرون می‌آورد."},{"v":36,"t":"لیکن به شما می‌گویم که هرسخن باطل که مردم گویند، حساب آن را در روزداوری خواهند داد."},{"v":37,"t":"زیرا که از سخنان خودعادل شمرده خواهی شد و از سخنهای تو بر توحکم خواهد شد.»"},{"v":38,"t":"آنگاه بعضی از کاتبان و فریسیان در جواب گفتند: «ای استاد می‌خواهیم از تو آیتی ببینیم.»"},{"v":39,"t":"او در جواب ایشان گفت: «فرقه شریر و زناکارآیتی می‌طلبند و بدیشان جز آیت یونس نبی داده نخواهد شد."},{"v":40,"t":"زیرا همچنانکه یونس سه شبانه‌روز در شکم ماهی ماند، پسر انسان نیز سه شبانه‌روز در شکم زمین خواهد بود."},{"v":41,"t":"مردمان نینوا درروز داوری با این طایفه برخاسته، بر ایشان حکم خواهند کرد زیرا که به موعظه یونس توبه کردند واینک بزرگتری از یونس در اینجا است."},{"v":42,"t":"ملکه جنوب در روز داوری با این فرقه برخاسته، برایشان حکم خواهد کرد زیرا که از اقصای زمین آمد تا حکمت سلیمان را بشنود، و اینک شخصی بزرگتر از سلیمان در اینجا است."},{"v":43,"t":"و وقتی که روح پلید از آدمی بیرون آید، درطلب راحت به‌جایهای بی‌آب گردش می‌کند ونمی یابد."},{"v":44,"t":"پس می‌گوید “به خانه خود که از آن بیرون آمدم برمی گردم، “ و چون آید، آن را خالی و جاروب شده و آراسته می‌بیند."},{"v":45,"t":"آنگاه می‌رود و هفت روح دیگر بدتر از خود رابرداشته، می‌آورد و داخل گشته، ساکن آنجامی شوند و انجام آن شخص بدتر از آغازش می‌شود. همچنین به این فرقه شریر خواهد شد.»"},{"v":46,"t":"او با آن جماعت هنوز سخن می‌گفت که ناگاه مادر و برادرانش در طلب گفتگوی وی بیرون ایستاده بودند."},{"v":47,"t":"و شخصی وی را گفت: «اینک مادر تو و برادرانت بیرون ایستاده، می‌خواهند باتو سخن گویند.»"},{"v":48,"t":"در جواب قایل گفت: «کیست مادر من و برادرانم کیانند؟»"},{"v":49,"t":"و دست خود را به سوی شاگردان خود دراز کرده، گفت: «اینانند مادر من و برادرانم."},{"v":50,"t":"زیرا هر‌که اراده پدر مرا که در آسمان است به‌جا آورد، همان برادر و خواهر و مادر من است.»"}]},"13":{"fa":[{"v":1,"t":"و در همان روز، عیسی از خانه بیرون آمده، به کناره دریا نشست"},{"v":2,"t":"و گروهی بسیار بر وی جمع آمدند، بقسمی که او به کشتی سوار شده، قرار گرفت و تمامی آن گروه بر ساحل ایستادند؛"},{"v":3,"t":"و معانی بسیار به مثلها برای ایشان گفت: «وقتی برزگری بجهت پاشیدن تخم بیرون شد."},{"v":4,"t":"و چون تخم می‌پاشید، قدری در راه افتاد ومرغان آمده، آن را خوردند."},{"v":5,"t":"و بعضی برسنگلاخ جایی که خاک زیاد نداشت افتاده، بزودی سبز شد، چونکه زمین عمق نداشت،"},{"v":6,"t":"وچون آفتاب برآمد بسوخت و چون ریشه نداشت خشکید."},{"v":7,"t":"و بعضی در میان خارها ریخته شد وخارها نمو کرده، آن را خفه نمود."},{"v":8,"t":"و برخی درزمین نیکو کاشته شده، بار آورد، بعضی صد وبعضی شصت و بعضی سی."},{"v":9,"t":"هر‌که گوش شنوادارد بشنود.»"},{"v":10,"t":"آنگاه شاگردانش آمده، به وی گفتند: «ازچه جهت با اینها به مثلها سخن می‌رانی؟»"},{"v":11,"t":"درجواب ایشان گفت: «دانستن اسرار ملکوت آسمان به شما عطا شده است، لیکن بدیشان عطانشده،"},{"v":12,"t":"زیرا هر‌که دارد بدو داده شود و افزونی یابد. اما کسی‌که ندارد آنچه دارد هم از او گرفته خواهد شد."},{"v":13,"t":"از این جهت با اینها به مثلها سخن می گویم که نگرانند و نمی بینند و شنوا هستند ونمی شنوند و نمی فهمند."},{"v":14,"t":"و در حق ایشان نبوت اشعیا تمام می‌شود که می‌گوید: “به سمع خواهید شنید و نخواهید فهمید و نظر کرده، خواهید نگریست و نخواهید دید."},{"v":15,"t":"زیرا قلب این قوم سنگین شده و به گوشها به سنگینی شنیده‌اند و چشمان خود را بر هم نهاده‌اند، مبادابه چشمها ببینند و به گوشها بشنوند و به دلهابفهمند و بازگشت کنند و من ایشان را شفا دهم.”"},{"v":16,"t":"لیکن خوشابه‌حال چشمان شما زیرا که می‌بینند و گوشهای شما زیرا که می‌شنوند"},{"v":17,"t":"زیرا هرآینه به شما می‌گویم بسا انبیا وعادلان خواستند که آنچه شما می‌بینید، ببینندو ندیدند و آنچه می‌شنوید، بشنوند ونشنیدند."},{"v":18,"t":"پس شما مثل برزگر را بشنوید."},{"v":19,"t":"کسی‌که کلمه ملکوت را شنیده، آن را نفهمید، شریرمی آید و آنچه در دل او کاشته شده است می‌رباید، همان است آنکه در راه کاشته شده است."},{"v":20,"t":"و آنکه بر سنگلاخ ریخته شده، اوست که کلام را شنیده، فی الفور به خشنودی قبول می‌کند،"},{"v":21,"t":"و لکن ریشه‌ای در خود ندارد، بلکه فانی است و هرگاه سختی یا صدمه‌ای به‌سبب کلام بر او وارد آید، در ساعت لغزش می‌خورد."},{"v":22,"t":"و آنکه در میان خارها ریخته شد، آن است که کلام را بشنود واندیشه این جهان و غرور دولت، کلام را خفه کند و بی‌ثمر گردد."},{"v":23,"t":"و آنکه درزمین نیکو کاشته شد، آن است که کلام را شنیده، آن را می‌فهمد و بارآور شده، بعضی صد و بعضی شصت و بعضی سی ثمر می‌آورد.»"},{"v":24,"t":"و مثلی دیگر بجهت ایشان آورده، گفت: «ملکوت آسمان مردی را ماند که تخم نیکو درزمین خود کاشت:"},{"v":25,"t":"و چون مردم در خواب بودند دشمنش آمده، در میان گندم، کرکاس ریخته، برفت."},{"v":26,"t":"و وقتی که گندم رویید و خوشه برآورد، کرکاس نیز ظاهر شد."},{"v":27,"t":"پس نوکران صاحب‌خانه آمده، به وی عرض کردند: “ای آقامگر تخم نیکو در زمین خویش نکاشته‌ای؟ پس ازکجا کرکاس بهم رسانید؟”"},{"v":28,"t":"ایشان را فرمود: “این کار دشمن است.” عرض کردند: “آیامی خواهی برویم آنها را جمع کنیم؟”"},{"v":29,"t":"فرمود: “نی، مبادا وقت جمع کردن کرکاس، گندم را باآنها برکنید."},{"v":30,"t":"بگذارید که هر دو تا وقت حصاد باهم نمو کنند و در موسم حصاد، دروگران راخواهم گفت که اول کرکاسها را جمع کرده، آنهارا برای سوختن بافه‌ها ببندید اما گندم را در انبارمن ذخیره کنید.”» مثل دانه خردل"},{"v":31,"t":"بار دیگر مثلی برای ایشان زده، گفت: «ملکوت آسمان مثل دانه خردلی است که شخصی گرفته، در مزرعه خویش کاشت."},{"v":32,"t":"وهرچند از سایر دانه‌ها کوچکتر است، ولی چون نمو کند بزرگترین بقول است و درختی می‌شودچنانکه مرغان هوا آمده در شاخه هایش آشیانه می گیرند.»"},{"v":33,"t":"و مثلی دیگر برای ایشان گفت که ملکوت آسمان خمیرمایه‌ای را ماند که زنی آن را گرفته، در سه کیل خمیر پنهان کرد تا تمام، مخمر گشت."},{"v":34,"t":"همه این معانی را عیسی با آن گروه به مثلهاگفت و بدون مثل بدیشان هیچ نگفت،"},{"v":35,"t":"تا تمام گردد کلامی که به زبان نبی گفته شد: «دهان خودرا به مثلها باز می‌کنم و به چیزهای مخفی شده ازبنای عالم تنطق خواهم کرد.»"},{"v":36,"t":"آنگاه عیسی آن گروه را مرخص کرده، داخل خانه گشت و شاگردانش نزد وی آمده، گفتند: «مثل کرکاس مزرعه را بجهت ما شرح فرما.»"},{"v":37,"t":"در جواب ایشان گفت: «آنکه بذر نیکومی کارد پسر انسان است،"},{"v":38,"t":"و مزرعه، این جهان است و تخم نیکو ابنای ملکوت و کرکاسها، پسران شریرند."},{"v":39,"t":"و دشمنی که آنها را کاشت، ابلیس است و موسم حصاد، عاقبت این عالم ودروندگان، فرشتگانند."},{"v":40,"t":"پس همچنان‌که کرکاسها را جمع کرده، در آتش می‌سوزانند، همانطور در عاقبت این عالم خواهد شد،"},{"v":41,"t":"که پسر انسان ملائکه خود را فرستاده، همه لغزش دهندگان و بدکاران را جمع خواهند کرد،"},{"v":42,"t":"و ایشان را به تنور آتش خواهند انداخت، جایی که گریه و فشار دندان بود."},{"v":43,"t":"آنگاه عادلان در ملکوت پدر خود مثل آفتاب، درخشان خواهند شد. هر‌که گوش شنوا دارد بشنود."},{"v":44,"t":"«و ملکوت آسمان گنجی را ماند، مخفی شده در زمین که شخصی آن را یافته، پنهان نمودو از خوشی آن رفته، آنچه داشت فروخت و آن زمین را خرید."},{"v":45,"t":"«باز ملکوت آسمان تاجری را ماند که جویای مرواریدهای خوب باشد،"},{"v":46,"t":"و چون یک مروارید گرانبها یافت، رفت و مایملک خود رافروخته، آن را خرید."},{"v":47,"t":"«ایض ملکوت آسمان مثل دامی است که به دریا افکنده شود و از هر جنسی به آن درآید،"},{"v":48,"t":"وچون پر شود، به کناره‌اش کشند و نشسته، خوبهارا در ظروف جمع کنند و بدها را دور اندازند."},{"v":49,"t":"بدینطور در آخر این عالم خواهد شد. فرشتگان بیرون آمده، طالحین را از میان صالحین جدا کرده،"},{"v":50,"t":"ایشان را در تنور آتش خواهندانداخت، جایی که گریه و فشار دندان می‌باشد.»"},{"v":51,"t":"عیسی ایشان را گفت: «آیا همه این امور رافهمیده‌اید؟» گفتندش: «بلی خداوندا.»"},{"v":52,"t":"به ایشان گفت: «بنابراین، هر کاتبی که در ملکوت آسمان تعلیم یافته است، مثل صاحب‌خانه‌ای است که از خزانه خویش چیزهای نو و کهنه بیرون می‌آورد.»"},{"v":53,"t":"و چون عیسی این مثلها را به اتمام رسانید، از آن موضع روانه شد."},{"v":54,"t":"و چون به وطن خویش آمد، ایشان را در کنیسه ایشان تعلیم داد، بقسمی که متعجب شده، گفتند: «از کجا این شخص چنین حکمت و معجزات را بهم رسانید؟"},{"v":55,"t":"آیا این پسر نجار نمی باشد؟ و آیا مادرش مریم نامی نیست؟ و برادرانش یعقوب و یوسف و شمعون ویهودا؟"},{"v":56,"t":"و همه خواهرانش نزد ما نمی باشند؟ پس این همه را از کجا بهم رسانید؟»"},{"v":57,"t":"و درباره او لغزش خوردند. لیکن عیسی بدیشان گفت: «نبی بی‌حرمت نباشد مگر در وطن و خانه خویش.»"},{"v":58,"t":"و به‌سبب بی‌ایمانی‌ایشان معجزه بسیار در آنجا ظاهر نساخت."}]},"14":{"fa":[{"v":1,"t":"در آن هنگام هیرودیس تیترارخ چون شهرت عیسی را شنید،"},{"v":2,"t":"به خادمان خود گفت: «این است یحیی تعمید‌دهنده که ازمردگان برخاسته است، و از این جهت معجزات از او صادر می‌گردد.»"},{"v":3,"t":"زیرا که هیرودیس یحیی را بخاطر هیرودیا، زن برادر خود فیلپس گرفته، در بند نهاده و در زندان انداخته بود؛"},{"v":4,"t":"چون که یحیی بدو همی گفت: «نگاه داشتن وی بر تو حلال نیست.»"},{"v":5,"t":"و وقتی که قصد قتل او کرد، از مردم ترسید زیرا که او را نبی می‌دانستند."},{"v":6,"t":"اما چون بزم میلاد هیرودیس را می‌آراستند، دختر هیرودیا درمجلس رقص کرده، هیرودیس را شاد نمود."},{"v":7,"t":"از این‌رو قسم خورده، وعده داد که آنچه خواهدبدو بدهد."},{"v":8,"t":"و او از ترغیب مادر خود گفت که «سریحیی تعمید‌دهنده را الان در طبقی به من عنایت فرما.»"},{"v":9,"t":"آنگاه پادشاه برنجید، لیکن بجهت پاس قسم و خاطر همنشینان خود، فرمود که بدهند."},{"v":10,"t":"و فرستاده، سر یحیی را در زندان از تن جدا کرد،"},{"v":11,"t":"و سر او را در طشتی گذارده، به دختر تسلیم نمودند و او آن را نزد مادر خود برد."},{"v":12,"t":"پس شاگردانش آمده، جسد او را برداشته، به خاک سپردند و رفته، عیسی را اطلاع دادند."},{"v":13,"t":"و چون عیسی این را شنید، به کشتی سوارشده، از آنجا به ویرانه‌ای به خلوت رفت. و چون مردم شنیدند، از شهرها به راه خشکی از عقب وی روانه شدند."},{"v":14,"t":"پس عیسی بیرون آمده، گروهی بسیار دیده، بر ایشان رحم فرمود وبیماران ایشان را شفا داد."},{"v":15,"t":"و در وقت عصر، شاگردانش نزد وی آمده، گفتند: «این موضع ویرانه است و وقت الان گذشته. پس این گروه رامرخص فرما تا به دهات رفته بجهت خود غذابخرند.»"},{"v":16,"t":"عیسی ایشان را گفت: «احتیاج به رفتن ندارند. شما ایشان را غذا دهید.»"},{"v":17,"t":"بدو گفتند: «در اینجا جز پنج نان و دو ماهی نداریم!»"},{"v":18,"t":"گفت: «آنها را اینجا به نزد من بیاورید!»"},{"v":19,"t":"وبدان جماعت فرمود تا بر سبزه نشستند و پنج نان و دو ماهی را گرفته، به سوی آسمان نگریسته، برکت داد و نان را پاره کرده، به شاگردان سپرد وشاگردان بدان جماعت."},{"v":20,"t":"و همه خورده، سیر شدند و از پاره های باقی‌مانده دوازده سبد پرکرده، برداشتند."},{"v":21,"t":"و خورندگان سوای زنان واطفال قریب به پنج هزار مرد بودند."},{"v":22,"t":"بی‌درنگ عیسی شاگردان خود را اصرارنمود تا به کشتی سوار شده، پیش از وی به کناره دیگر روانه شوند تا آن گروه را رخصت دهد."},{"v":23,"t":"وچون مردم را روانه نمود، به خلوت برای عبادت بر فراز کوهی برآمد. و وقت شام در آنجا تنها بود."},{"v":24,"t":"اما کشتی در آن وقت در میان دریا به‌سبب بادمخالف که می‌وزید، به امواج گرفتار بود."},{"v":25,"t":"و درپاس چهارم از شب، عیسی بر دریا خرامیده، به سوی ایشان روانه گردید."},{"v":26,"t":"اما چون شاگردان، او را بر دریا خرامان دیدند، مضطرب شده، گفتندکه خیالی است؛ و از خوف فریاد برآوردند."},{"v":27,"t":"اماعیسی ایشان را بی‌تامل خطاب کرده، گفت: «خاطر جمع دارید! منم ترسان مباشید!»"},{"v":28,"t":"پطرس در جواب او گفت: «خداوندا، اگر تویی مرا بفرما تا بر روی آب، نزد تو آیم.»"},{"v":29,"t":"گفت: «بیا!» در ساعت پطرس از کشتی فرود شده، برروی آب روانه شد تا نزد عیسی آید."},{"v":30,"t":"لیکن چون باد را شدید دید، ترسان گشت و مشرف به غرق شده، فریاد برآورده، گفت: «خداوندا مرادریاب.»"},{"v":31,"t":"عیسی بی‌درنگ دست آورده، او رابگرفت و گفت: «ای کم‌ایمان، چرا شک آوردی؟»"},{"v":32,"t":"و چون به کشتی سوار شدند، بادساکن گردید."},{"v":33,"t":"پس اهل کشتی آمده، او راپرستش کرده، گفتند: «فی الحقیقه تو پسر خدا هستی!»"},{"v":34,"t":"آنگاه عبور کرده، به زمین جنیسره آمدند،"},{"v":35,"t":"و اهل آن موضع او را شناخته، به همگی آن نواحی فرستاده، همه بیماران را نزد او آوردند،"},{"v":36,"t":"و از او اجازت خواستند که محض دامن ردایش را لمس کنند و هر‌که لمس کرد، صحت کامل یافت."}]},"15":{"fa":[{"v":1,"t":"آنگاه کاتبان و فریسیان اورشلیم نزدعیسی آمده، گفتند:"},{"v":2,"t":"«چون است که شاگردان تو از تقلید مشایخ تجاوز می‌نمایند، زیرا هرگاه نان می‌خورند دست خود رانمی شویند؟»"},{"v":3,"t":"او در جواب ایشان گفت: «شمانیز به تقلید خویش، از حکم خدا چرا تجاوزمی کنید؟"},{"v":4,"t":"زیرا خدا حکم داده است که مادر وپدر خود را حرمت دار و هرکه پدر یا مادر رادشنام دهد البته هلاک گردد."},{"v":5,"t":"لیکن شمامی گویید هر‌که پدر یا مادر خود را گوید آنچه ازمن به تو نفع رسد هدیه‌ای است،"},{"v":6,"t":"و پدر یا مادرخود را بعد از آن احترام نمی نماید. پس به تقلیدخود، حکم خدا را باطل نموده‌اید."},{"v":7,"t":"‌ای ریاکاران، اشعیاء در باره شما نیکو نبوت نموده است که گفت:"},{"v":8,"t":"این قوم به زبانهای خود به من تقرب می‌جویند و به لبهای خویش مرا تمجیدمی نمایند، لیکن دلشان از من دور است."},{"v":9,"t":"پس عبادت مرا عبث می‌کنند زیرا که احکام مردم رابمنزله فرایض تعلیم می‌دهند.»"},{"v":10,"t":"و آن جماعت را خوانده، بدیشان گفت: «گوش داده، بفهمید؛"},{"v":11,"t":"نه آنچه به دهان فرومی رود انسان را نجس می‌سازد بلکه آنچه از دهان بیرون می‌آید انسان را نجس می‌گرداند.»"},{"v":12,"t":"آنگاه شاگردان وی آمده، گفتند: «آیا می‌دانی که فریسیان چون این سخن را شنیدند، مکروهش داشتند؟»"},{"v":13,"t":"او در جواب گفت: «هر نهالی که پدرآسمانی من نکاشته باشد، کنده شود."},{"v":14,"t":"ایشان راواگذارید، کوران راهنمایان کورانند و هرگاه کور، کور را راهنما شود، هر دو در چاه افتند."},{"v":15,"t":"پطرس در جواب او گفت: «این مثل را برای ما شرح فرما.»"},{"v":16,"t":"عیسی گفت: «آیا شما نیز تا به حال بی‌ادراک هستید؟"},{"v":17,"t":"یا هنوز نیافته‌اید که آنچه از دهان فرو می‌رود، داخل شکم می‌گردد ودر مبرز افکنده می‌شود؟"},{"v":18,"t":"لیکن آنچه از دهان برآید، از دل صادر می‌گردد و این چیزها است که انسان را نجس می‌سازد."},{"v":19,"t":"زیرا که از دل برمی آید، خیالات بد و قتلها و زناها و فسقها ودزدیها و شهادات دروغ و کفرها."},{"v":20,"t":"اینها است که انسان را نجس می‌سازد، لیکن خوردن به‌دستهای ناشسته، انسان را نجس نمی گرداند.»"},{"v":21,"t":"پس عیسی از آنجا بیرون شده، به دیارصور و صیدون رفت."},{"v":22,"t":"ناگاه زن کنعانیه‌ای از آن حدود بیرون آمده، فریاد‌کنان وی را گفت: «خداوندا، پسر داودا، بر من رحم کن زیرا دختر من سخت دیوانه است.»"},{"v":23,"t":"لیکن هیچ جوابش نداد تا شاگردان او پیش آمده، خواهش نمودند که «او را مرخص فرمای زیرا در عقب ما شورش می‌کند.»"},{"v":24,"t":"او در جواب گفت: «فرستاده نشده‌ام مگر بجهت گوسفندان گم شده خاندان اسرائیل.»"},{"v":25,"t":"پس آن زن آمده، او را پرستش کرده، گفت: «خداوندا مرا یاری کن.»"},{"v":26,"t":"در جواب گفت که «نان فرزندان را گرفتن و نزد سگان انداختن جایزنیست.»"},{"v":27,"t":"عرض کرد: «بلی خداوندا، زیرا سگان نیز از پاره های افتاده سفره آقایان خویش می‌خورند.»"},{"v":28,"t":"آنگاه عیسی در جواب او گفت: «ای زن! ایمان تو عظیم است! تو را برحسب خواهش تو بشود.» که در همان ساعت، دخترش شفا یافت."},{"v":29,"t":"عیسی از آنجا حرکت کرده، به کناره دریای جلیل آمد و برفراز کوه برآمده، آنجا بنشست."},{"v":30,"t":"و گروهی بسیار، لنگان و کوران و گنگان وشلان و جمعی از دیگران را با خود برداشته، نزداو آمدند و ایشان را بر پایهای عیسی افکندند وایشان را شفا داد،"},{"v":31,"t":"بقسمی که آن جماعت، چون گنگان را گویا و شلان را تندرست و لنگان راخرامان و کوران را بینا دیدند، متعجب شده، خدای اسرائیل را تمجید کردند."},{"v":32,"t":"عیسی شاگردان خود را پیش طلبیده، گفت: «مرا بر این جماعت دل بسوخت زیرا که الحال سه روز است که با من می‌باشند و هیچ‌چیز برای خوراک ندارند و نمی خواهم ایشان را گرسنه برگردانم مبادا در راه ضعف کنند.»"},{"v":33,"t":"شاگردانش به او گفتند: «از کجا در بیابان ما را آنقدر نان باشدکه چنین انبوه را سیر کند؟»"},{"v":34,"t":"عیسی ایشان راگفت: «چند نان دارید؟» گفتند: «هفت نان و قدری از ماهیان کوچک.»"},{"v":35,"t":"پس مردم را فرمود تا برزمین بنشینند."},{"v":36,"t":"و آن هفت نان و ماهیان را گرفته، شکر نمود و پاره کرده، به شاگردان خود داد وشاگردان به آن جماعت."},{"v":37,"t":"و همه خورده، سیرشدند و از خرده های باقی‌مانده هفت زنبیل پربرداشتند."},{"v":38,"t":"و خورندگان، سوای زنان و اطفال چهار هزار مرد بودند."},{"v":39,"t":"پس آن گروه را رخصت داد و به کشتی سوار شده، به حدود مجدل آمد."}]},"16":{"fa":[{"v":1,"t":"آنگاه فریسیان و صدوقیان نزد او آمده، از روی امتحان از وی خواستند که آیتی آسمانی برای ایشان ظاهر سازد."},{"v":2,"t":"ایشان راجواب داد که «در وقت عصر می‌گویید هوا خوش خواهد بود زیرا آسمان سرخ است؛"},{"v":3,"t":"وصبحگاهان می‌گویید امروز هوا بد خواهد شدزیرا که آسمان سرخ و گرفته است. ای ریاکاران می‌دانید صورت آسمان را تمییز دهید، اماعلامات زمانها را نمی توانید!"},{"v":4,"t":"فرقه شریر زناکار، آیتی می‌طلبند و آیتی بدیشان عطا نخواهد شدجز آیت یونس نبی.» پس ایشان را رها کرده، روانه شد."},{"v":5,"t":"و شاگردانش چون بدان طرف می‌رفتند، فراموش کردند که نان بردارند."},{"v":6,"t":"عیسی ایشان راگفت: «آگاه باشید که از خمیرمایه فریسیان وصدوقیان احتیاط کنید!»"},{"v":7,"t":"پس ایشان در خودتفکر نموده، گفتند: «از آن است که نان برنداشته‌ایم.»"},{"v":8,"t":"عیسی این را درک نموده، بدیشان گفت: «ای سست‌ایمانان، چرا در خود تفکرمی کنید از آنجهت که نان نیاورده‌اید؟"},{"v":9,"t":"آیا هنوزنفهمیده و یاد نیاورده‌اید آن پنج نان و پنج هزارنفر و چند سبدی را که برداشتید؟"},{"v":10,"t":"و نه آن هفت نان و چهار هزار نفر و چند زنبیلی را که برداشتید؟»"},{"v":11,"t":"پس چرا نفهمیدید که درباره نان شما را نگفتم که از خمیرمایه فریسیان وصدوقیان احتیاط کنید؟»"},{"v":12,"t":"آنگاه دریافتند که نه از خمیرمایه نان بلکه از تعلیم فریسیان وصدوقیان حکم به احتیاط فرموده است."},{"v":13,"t":"و هنگامی که عیسی به نواحی قیصریه فیلپس آمد، از شاگردان خود پرسیده، گفت: «مردم مرا که پسر انسانم چه شخص می‌گویند؟»"},{"v":14,"t":"گفتند: «بعضی یحیی تعمید‌دهنده و بعضی الیاس و بعضی ارمیا یا یکی از انبیا.»"},{"v":15,"t":"ایشان راگفت: «شما مرا که می‌دانید؟»"},{"v":16,"t":"شمعون پطرس در جواب گفت که «تویی مسیح، پسر خدای زنده!»"},{"v":17,"t":"عیسی در جواب وی گفت: «خوشابحال تو‌ای شمعون بن یونا! زیرا جسم وخون این را بر تو کشف نکرده، بلکه پدر من که درآسمان است."},{"v":18,"t":"و من نیز تو را می‌گویم که تویی پطرس و بر این صخره کلیسای خود را بنا می‌کنم و ابواب جهنم بر آن استیلا نخواهد یافت."},{"v":19,"t":"وکلیدهای ملکوت آسمان را به تو می‌سپارم؛ وآنچه بر زمین ببندی در آسمان بسته گردد و آنچه در زمین گشایی در آسمان گشاده شود."},{"v":20,"t":"آنگاه شاگردان خود را قدغن فرمود که به هیچ‌کس نگویند که او مسیح است."},{"v":21,"t":"و از آن زمان عیسی به شاگردان خودخبردادن آغاز کرد که رفتن او به اورشلیم وزحمت بسیار کشیدن از مشایخ و روسای کهنه وکاتبان و کشته شدن و در روز سوم برخاستن ضروری است."},{"v":22,"t":"و پطرس او را گرفته، شروع کرد به منع نمودن و گفت: «حاشا از تو‌ای خداوندکه این بر تو هرگز واقع نخواهد شد!»"},{"v":23,"t":"اما اوبرگشته، پطرس را گفت: «دور شو از من‌ای شیطان زیرا که باعث لغزش من می‌باشی، زیرا نه امورالهی را بلکه امور انسانی را تفکر می‌کنی!»"},{"v":24,"t":"آنگاه عیسی به شاگردان خود گفت: «اگر کسی خواهدمتابعت من کند، باید خود را انکار کرده وصلیب خود را برداشته، از عقب من آید."},{"v":25,"t":"زیرا هر کس بخواهد جان خود را برهاند، آن را هلاک سازد؛ اما هر‌که جان خود را بخاطر من هلاک کند، آن را دریابد."},{"v":26,"t":"زیرا شخص را چه سود دارد که تمام دنیا را ببرد و جان خود را ببازد؟ یا اینکه آدمی چه چیز را فدای جان خود خواهدساخت؟"},{"v":27,"t":"زیرا که پسر انسان خواهد آمد درجلال پدر خویش به اتفاق ملائکه خود و در آن وقت هر کسی را موافق اعمالش جزا خواهد داد."},{"v":28,"t":"هرآینه به شما می‌گویم که بعضی در اینجاحاضرند که تا پسر انسان را نبینند که در ملکوت خود می‌آید، ذائقه موت را نخواهند چشید.»"}]},"17":{"fa":[{"v":1,"t":"و بعد از شش روز، عیسی، پطرس ویعقوب و برادرش یوحنا را برداشته، ایشان را در خلوت به کوهی بلند برد."},{"v":2,"t":"و در نظرایشان هیات او متبدل گشت و چهره‌اش چون خورشید، درخشنده و جامه‌اش چون نور، سفیدگردید."},{"v":3,"t":"که ناگاه موسی و الیاس بر ایشان ظاهرشده، با او گفتگو می‌کردند."},{"v":4,"t":"اما پطرس به عیسی متوجه شده، گفت که «خداوندا، بودن ما در اینجانیکو است! اگر بخواهی، سه سایبان در اینجابسازیم، یکی برای تو و یکی بجهت موسی ودیگری برای الیاس.»"},{"v":5,"t":"و هنوز سخن بر زبانش بود که ناگاه ابری درخشنده بر ایشان سایه افکند واینک آوازی از ابر در‌رسید که «این است پسرحبیب من که از وی خشنودم. او را بشنوید!»"},{"v":6,"t":"وچون شاگردان این را شنیدند، به روی در‌افتاده، بینهایت ترسان شدند."},{"v":7,"t":"عیسی نزدیک آمده، ایشان را لمس نمود و گفت: «برخیزید و ترسان مباشید!»"},{"v":8,"t":"و چشمان خود را گشوده، هیچ‌کس راجز عیسی تنها ندیدند."},{"v":9,"t":"و چون ایشان از کوه به زیر می‌آمدند، عیسی ایشان را قدغن فرمود که «تاپسر انسان از مردگان برنخیزد، زنهار این‌رویا را به کسی باز نگویید.»"},{"v":10,"t":"شاگردانش از او پرسیده، گفتند: «پس کاتبان چرا می‌گویند که می‌بایدالیاس اول آید؟»"},{"v":11,"t":"او در جواب گفت: «البته الیاس می‌آید و تمام چیزها را اصلاح خواهدنمود."},{"v":12,"t":"لیکن به شما می‌گویم که الحال الیاس آمده است و او را نشناختند بلکه آنچه خواستندبا وی کردند؛ به همانطور پسر انسان نیز از ایشان زحمت خواهد دید."},{"v":13,"t":"آنگاه شاگردان دریافتندکه درباره یحیی تعمیددهنده بدیشان سخن می‌گفت."},{"v":14,"t":"و چون به نزد جماعت رسیدند، شخصی پیش آمده، نزد وی زانو زده، عرض کرد:"},{"v":15,"t":"«خداوندا، بر پسر من رحم کن زیرا مصروع و به شدت متالم است، چنانکه بارها در آتش و مکرر در آب می‌افتد."},{"v":16,"t":"و او را نزد شاگردان تو آوردم، نتوانستند او را شفا دهند.»"},{"v":17,"t":"عیسی در جواب گفت: «ای فرقه بی‌ایمان کج رفتار، تا به کی با شماباشیم و تا چند متحمل شما گردم؟ او را نزد من آورید.»"},{"v":18,"t":"پس عیسی او را نهیب داده، دیو ازوی بیرون شد و در ساعت، آن پسر شفا یافت."},{"v":19,"t":"اما شاگردان نزد عیسی آمده، در خلوت از اوپرسیدند: «چرا ما نتوانستیم او را بیرون کنیم؟"},{"v":20,"t":"عیسی ایشان را گفت: «به‌سبب بی‌ایمانی شما. زیرا هرآینه به شما می‌گویم، اگر ایمان به قدر دانه خردلی می‌داشتید، بدین کوه می‌گفتید از اینجابدانجا منتقل شو، البته منتقل می‌شد و هیچ امری بر شما محال نمی بود."},{"v":21,"t":"لیکن این جنس جز به دعا و روزه بیرون نمی رود.»"},{"v":22,"t":"و چون ایشان در جلیل می‌گشتند، عیسی بدیشان گفت: «پسر انسان بدست مردم تسلیم کرده خواهد شد،"},{"v":23,"t":"و او را خواهند کشت و درروز سوم خواهد برخاست.» پس بسیار محزون شدند."},{"v":24,"t":"و چون ایشان وارد کفرناحوم شدند، محصلان دو درهم نزد پطرس آمده، گفتند: «آیااستاد شما دو درهم را نمی دهد؟»"},{"v":25,"t":"گفت: «بلی.» و چون به خانه درآمده، عیسی بر او سبقت نموده، گفت: «ای شمعون، چه گمان داری؟ پادشاهان جهان از چه کسان عشر و جزیه می‌گیرند؟ از فرزندان خویش یا از بیگانگان؟»"},{"v":26,"t":"پطرس به وی گفت: «از بیگانگان.» عیسی بدوگفت: «پس یقین پسران آزادند!"},{"v":27,"t":"لیکن مبادا که ایشان را برنجانیم، به کناره دریا رفته، قلابی بینداز و اول ماهی که بیرون می‌آید، گرفته و دهانش راباز کرده، مبلغ چهار درهم خواهی یافت. آن رابرداشته، برای من و خود بدیشان بده!»"}]},"18":{"fa":[{"v":1,"t":"در همان ساعت، شاگردان نزد عیسی آمده، گفتند: «چه کس در ملکوت آسمان بزرگتر است؟»"},{"v":2,"t":"آنگاه عیسی طفلی طلب نموده، در میان ایشان برپا داشت"},{"v":3,"t":"و گفت: «هرآینه به شما می‌گویم تا بازگشت نکنید و مثل طفل کوچک نشوید، هرگز داخل ملکوت آسمان نخواهید شد."},{"v":4,"t":"پس هر‌که مثل این بچه کوچک خود را فروتن سازد، همان در ملکوت آسمان بزرگتر است."},{"v":5,"t":"و کسی‌که چنین طفلی را به اسم من قبول کند، مرا پذیرفته است."},{"v":6,"t":"و هر‌که یکی ازاین صغار را که به من ایمان دارند، لغزش دهد او رابهتر می‌بود که سنگ آسیایی بر گردنش آویخته، در قعر دریا غرق می‌شد!"},{"v":7,"t":"وای بر این جهان به‌سبب لغزشها؛ زیرا که لابد است از وقوع لغزشها، لیکن وای بر کسی‌که سبب لغزش باشد."},{"v":8,"t":"پس اگر دستت یا پایت تو رابلغزاند، آن را قطع کرده، از خود دور انداز زیرا تورا بهتر است که لنگ یا شل داخل حیات شوی ازآنکه با دو دست یا دو پا در نار جاودانی افکنده شوی."},{"v":9,"t":"و اگر چشمت تو را لغزش دهد، آن را قلع کرده، از خود دور انداز زیرا تو را بهتر است بایک چشم وارد حیات شوی، از اینکه با دو چشم در آتش جهنم افکنده شوی."},{"v":10,"t":"زنهار یکی از این صغار را حقیر مشمارید، زیرا شما را می‌گویم که ملائکه ایشان دائم درآسمان روی پدر مرا که در آسمان است می‌بینند."},{"v":11,"t":"زیرا که پسر انسان آمده است تا گم شده رانجات‌بخشد."},{"v":12,"t":"شما چه گمان می‌برید، اگرکسی را صد گوسفند باشد و یکی از آنها گم شود، آیا آن نود و نه را به کوهسار نمی گذارد و به جستجوی آن گم شده نمی رود؟"},{"v":13,"t":"و اگر اتفاق آن را دریابد، هرآینه به شما می‌گویم بر آن یکی بیشتر شادی می‌کند از آن نود و نه که گم نشده‌اند."},{"v":14,"t":"همچنین اراده پدر شما که در آسمان است این نیست که یکی از این کوچکان هلاک گردد."},{"v":15,"t":"«و اگر برادرت به تو گناه کرده باشد، برو واو را میان خود و او در خلوت الزام کن. هرگاه سخن تو را گوش گرفت، برادر خود را دریافتی؛"},{"v":16,"t":"و اگر نشنود، یک یا دو نفر دیگر با خود بردار تااز زبان دو یا سه شاهد، هر سخنی ثابت شود."},{"v":17,"t":"واگر سخن ایشان را رد کند، به کلیسا بگو. و اگرکلیسا را قبول نکند، در نزد تو مثل خارجی یاباجگیر باشد."},{"v":18,"t":"هرآینه به شما می‌گویم آنچه برزمین بندید، در آسمان بسته شده باشد و آنچه برزمین گشایید، در آسمان گشوده شده باشد."},{"v":19,"t":"باز به شما می‌گویم هر گاه دو نفر از شما در زمین درباره هر‌چه که بخواهند متفق شوند، هرآینه ازجانب پدر من که در آسمان است برای ایشان کرده خواهد شد."},{"v":20,"t":"زیرا جایی که دو یا سه نفر به اسم من جمع شوند، آنجا درمیان ایشان حاضرم.»"},{"v":21,"t":"آنگاه پطرس نزد او آمده، گفت: «خداوندا، چند مرتبه برادرم به من خطا ورزد، می‌باید او راآمرزید؟ آیا تا هفت مرتبه؟»"},{"v":22,"t":"عیسی بدو گفت: «تو را نمی گویم تا هفت مرتبه، بلکه تا هفتاد هفت مرتبه!"},{"v":23,"t":"از آنجهت ملکوت آسمان پادشاهی راماند که با غلامان خود اراده محاسبه داشت."},{"v":24,"t":"وچون شروع به حساب نمود، شخصی را نزد اوآوردند که ده هزار قنطار به او بدهکار بود."},{"v":25,"t":"وچون چیزی نداشت که ادا نماید، آقایش امر کردکه او را با زن و فرزندان و تمام مایملک اوفروخته، طلب را وصول کنند."},{"v":26,"t":"پس آن غلام روبه زمین نهاده او را پرستش نمود و گفت: “ای آقامرا مهلت ده تا همه را به تو ادا کنم.”"},{"v":27,"t":"آنگاه آقای آن غلام بر وی ترحم نموده، او را رها کرد وقرض او را بخشید."},{"v":28,"t":"لیکن چون آن غلام بیرون رفت، یکی از همقطاران خود را یافت که از او صددینار طلب داشت. او را بگرفت و گلویش رافشرده، گفت: “طلب مرا ادا کن!”"},{"v":29,"t":"پس آن همقطار بر پایهای او افتاده، التماس نموده، گفت: “مرا مهلت ده تا همه را به تو رد کنم.”"},{"v":30,"t":"اما اوقبول نکرد بلکه رفته، او را در زندان انداخت تاقرض را ادا کند."},{"v":31,"t":"چون همقطاران وی این وقایع را دیدند، بسیار غمگین شده، رفتند و آنچه شده بود به آقای خود باز‌گفتند."},{"v":32,"t":"آنگاه مولایش او راطلبیده، گفت: “ای غلام شریر، آیا تمام آن قرض را محض خواهش تو به تو نبخشیدم؟"},{"v":33,"t":"پس آیاتو را نیز لازم نبود که بر همقطار خود رحم کنی چنانکه من بر تو رحم کردم؟”"},{"v":34,"t":"پس مولای او درغضب شده، او را به جلادان سپرد تا تمام قرض رابدهد."},{"v":35,"t":"به همینطور پدر آسمانی من نیز با شماعمل خواهد نمود، اگر هر یکی از شما برادر خودرا از دل نبخشد.»"}]},"19":{"fa":[{"v":1,"t":"و چون عیسی این سخنان را به اتمام رسانید، از جلیل روانه شده، به حدودیهودیه از آن طرف اردن آمد."},{"v":2,"t":"و گروهی بسیار ازعقب او آمدند و ایشان را در آنجا شفا بخشید."},{"v":3,"t":"پس فریسیان آمدند تا او را امتحان کنند وگفتند: «آیا جایز است مرد، زن خود را به هر علتی طلاق دهد؟»"},{"v":4,"t":"او در جواب ایشان گفت: «مگرنخوانده‌اید که خالق در ابتدا ایشان را مرد و زن آفرید،"},{"v":5,"t":"و گفت از این جهت مرد، پدر و مادرخود را رها کرده، به زن خویش بپیوندد و هر دویک تن خواهند شد؟"},{"v":6,"t":"بنابراین بعد از آن دونیستند بلکه یک تن هستند. پس آنچه را خداپیوست انسان جدا نسازد.»"},{"v":7,"t":"به وی گفتند: «پس از بهر‌چه موسی‌امر فرمود که زن را طلاقنامه دهند و جدا کنند؟»"},{"v":8,"t":"ایشان را گفت: «موسی به‌سبب سنگدلی شما، شما را اجازت داد که زنان خود را طلاق دهید. لیکن از ابتدا چنین نبود."},{"v":9,"t":"و به شما می‌گویم هر‌که زن خود را بغیر علت زناطلاق دهد و دیگری را نکاح کند، زانی است و هرکه زن مطلقه‌ای را نکاح کند، زنا کند.»"},{"v":10,"t":"شاگردانش بدو گفتند: «اگر حکم شوهر بازن چنین باشد، نکاح نکردن بهتر است!»"},{"v":11,"t":"ایشان را گفت: «تمامی خلق این کلام را نمی پذیرند، مگر به کسانی که عطا شده است."},{"v":12,"t":"زیرا که خصی‌ها می‌باشند که از شکم مادر چنین متولدشدند و خصی‌ها هستند که از مردم خصی شده‌اند و خصی‌ها می‌باشند که بجهت ملکوت خدا خود را خصی نموده‌اند. آنکه توانایی قبول دارد بپذیرد.»"},{"v":13,"t":"آنگاه چند بچه کوچک را نزد او آوردند تادستهای خود را بر ایشان نهاده، دعا کند. اماشاگردان، ایشان را نهیب دادند."},{"v":14,"t":"عیسی گفت: «بچه های کوچک را بگذارید و از آمدن نزد من، ایشان را منع مکنید، زیرا ملکوت آسمان از مثل اینها است.»"},{"v":15,"t":"و دستهای خود را بر ایشان گذارده از آن جا روانه شد."},{"v":16,"t":"ناگاه شخصی آمده، وی را گفت: «ای استادنیکو، چه عمل نیکو کنم تا حیات جاودانی یابم؟»"},{"v":17,"t":"وی را گفت: «از چه سبب مرا نیکو گفتی و حال آنکه کسی نیکو نیست، جز خدا فقط. لیکن اگربخواهی داخل حیات شوی، احکام را نگاه دار.»"},{"v":18,"t":"بدو گفت: «کدام احکام؟» عیسی گفت: «قتل مکن، زنا مکن، دزدی مکن، شهادت دروغ مده،"},{"v":19,"t":"و پدر و مادر خود را حرمت دار و همسایه خود را مثل نفس خود دوست دار.»"},{"v":20,"t":"جوان وی را گفت: «همه اینها را از طفولیت نگاه داشته‌ام. دیگر مرا چه ناقص است؟»"},{"v":21,"t":"عیسی بدو گفت: «اگر بخواهی کامل شوی، رفته مایملک خود رابفروش و به فقراء بده که در آسمان گنجی خواهی داشت؛ و آمده مرا متابعت نما.»"},{"v":22,"t":"چون جوان این سخن را شنید، دل تنگ شده، برفت زیرا که مال بسیار داشت."},{"v":23,"t":"عیسی به شاگردان خود گفت: «هرآینه به شما می‌گویم که شخص دولتمند به ملکوت آسمان به دشواری داخل می‌شود."},{"v":24,"t":"و باز شمارا می‌گویم که گذشتن شتر از سوراخ سوزن، آسانتر است از دخول شخص دولتمند درملکوت خدا.»"},{"v":25,"t":"شاگردان چون شنیدند، بغایت متحیر گشته، گفتند: «پس که می‌تواند نجات یابد؟»"},{"v":26,"t":"عیسی متوجه ایشان شده، گفت: «نزدانسان این محال است لیکن نزد خدا همه‌چیزممکن است.»"},{"v":27,"t":"آنگاه پطرس در جواب گفت: «اینک ما همه‌چیزها را ترک کرده، تو را متابعت می‌کنیم. پس ما را چه خواهد بود؟»"},{"v":28,"t":"«عیسی ایشان را گفت: «هرآینه به شما می‌گویم شما که مرا متابعت نموده‌اید، در معاد وقتی که پسر انسان بر کرسی جلال خود نشیند، شما نیز به دوازده کرسی نشسته، بر دوازده سبط اسرائیل داوری خواهید نمود."},{"v":29,"t":"و هر‌که بخاطر اسم من، خانه هایا برادران یا خواهران یا پدر یا مادر یا زن یافرزندان یا زمینها را ترک کرد، صد چندان خواهدیافت و وارث حیات جاودانی خواهد گشت."},{"v":30,"t":"لیکن بسا اولین که آخرین می‌گردند و آخرین، اولین!"}]},"20":{"fa":[{"v":1,"t":"«زیرا ملکوت آسمان صاحب‌خانه‌ای را ماند که بامدادان بیرون رفت تا عمله بجهت تاکستان خود به مزد بگیرد."},{"v":2,"t":"پس با عمله، روزی یک دینار قرار داده، ایشان را به تاکستان خود فرستاد."},{"v":3,"t":"و قریب به ساعت سوم بیرون رفته، بعضی دیگر را در بازار بیکار ایستاده دید."},{"v":4,"t":"ایشان را نیز گفت: “شما هم به تاکستان بروید وآنچه حق شما است به شما می‌دهم.” پس رفتند."},{"v":5,"t":"باز قریب به ساعت ششم و نهم رفته، همچنین کرد."},{"v":6,"t":"و قریب به ساعت یازدهم رفته، چند نفردیگر بیکار ایستاده یافت. ایشان را گفت: “از بهرچه تمامی روز در اینجا بیکار ایستاده‌اید؟”"},{"v":7,"t":"گفتندش: “هیچ‌کس ما را به مزد نگرفت.” بدیشان گفت: “شما نیز به تاکستان بروید و حق خویش راخواهید یافت.”"},{"v":8,"t":"و چون وقت شام رسید، صاحب تاکستان به ناظر خود گفت: “مزدوران راطلبیده، از آخرین گرفته تا اولین مزد ایشان را اداکن.”"},{"v":9,"t":"پس یازده ساعتیان آمده، هر نفری دیناری یافتند."},{"v":10,"t":"و اولین آمده، گمان بردند که بیشترخواهند یافت. ولی ایشان نیز هر نفری دیناری یافتند."},{"v":11,"t":"اما چون گرفتند، به صاحب‌خانه شکایت نموده،"},{"v":12,"t":"گفتند که “این آخرین، یک ساعت کار کردند و ایشان را با ما که متحمل سختی و حرارت روز گردیده‌ایم مساوی ساخته‌ای؟”"},{"v":13,"t":"او در جواب یکی از ایشان گفت: “ای رفیق بر تو ظلمی نکردم. مگر به دیناری با من قرار ندادی؟"},{"v":14,"t":"حق خود را گرفته برو. می‌خواهم بدین آخری مثل تو دهم."},{"v":15,"t":"آیا مرا جایز نیست که از مال خود آنچه خواهم بکنم؟ مگر چشم توبد است از آن رو که من نیکو هستم؟”"},{"v":16,"t":"بنابراین اولین آخرین و آخرین اولین خواهند شد، زیراخوانده‌شدگان بسیارند و برگزیدگان کم.»"},{"v":17,"t":"و چون عیسی به اورشلیم می‌رفت، دوازده شاگرد خود را در اثنای راه به خلوت طلبیده بدیشان گفت:"},{"v":18,"t":"«اینک به سوی اورشلیم می‌رویم و پسر انسان به روسای کهنه و کاتبان تسلیم کرده خواهد شد و حکم قتل او را خواهندداد،"},{"v":19,"t":"و او را به امت‌ها خواهند سپرد تا او رااستهزا کنند و تازیانه زنند و مصلوب نمایند و درروز سوم خواهد برخاست.»"},{"v":20,"t":"آنگاه مادر دو پسر زبدی با پسران خود نزدوی آمده و پرستش نموده، از او چیزی درخواست کرد."},{"v":21,"t":"بدو گفت: «چه خواهش داری؟» گفت: «بفرما تا این دو پسر من در ملکوت تو، یکی بر دست راست و دیگری بر دست چپ تو بنشینند.»"},{"v":22,"t":"عیسی در جواب گفت: «نمی دانید چه می‌خواهید. آیا می‌توانید از آن کاسه‌ای که من می‌نوشم، بنوشید و تعمیدی را که من می‌یابم، بیابید؟» بدو گفتند: «می‌توانیم.»"},{"v":23,"t":"ایشان را گفت: «البته از کاسه من خواهیدنوشید و تعمیدی را که من می‌یابم، خواهید یافت. لیکن نشستن به‌دست راست و چپ من، از آن من نیست که بدهم، مگر به کسانی که از جانب پدرم برای ایشان مهیا شده است.»"},{"v":24,"t":"اما چون آن ده شاگرد شنیدند، بر آن دوبرادر به دل رنجیدند."},{"v":25,"t":"عیسی ایشان را پیش طلبیده، گفت: «آگاه هستید که حکام امت‌ها برایشان سروری می‌کنند و روسا بر ایشان مسلطند."},{"v":26,"t":"لیکن در میان شما چنین نخواهد بود، بلکه هرکه در میان شما می‌خواهد بزرگ گردد، خادم شماباشد."},{"v":27,"t":"و هر‌که می‌خواهد در میان شما مقدم بود، غلام شما باشد."},{"v":28,"t":"چنانکه پسر انسان نیامدتا مخدوم شود بلکه تا خدمت کند و جان خود رادر راه بسیاری فدا سازد.»"},{"v":29,"t":"و هنگامی که از اریحا بیرون می‌رفتند، گروهی بسیار از عقب او می‌آمدند."},{"v":30,"t":"که ناگاه دومرد کور کنار راه نشسته، چون شنیدند که عیسی در گذر است، فریاد کرده، گفتند: «خداوندا، پسرداودا، بر ما ترحم کن!»"},{"v":31,"t":"و هر‌چند خلق ایشان را نهیب می‌دادند که خاموش شوند، بیشتر فریادکنان می‌گفتند: «خداوندا، پسر داودا، بر ما ترحم فرما!»"},{"v":32,"t":"پس عیسی ایستاده، به آواز بلند گفت: «چه می‌خواهید برای شما کنم؟»"},{"v":33,"t":"به وی گفتند: «خداوندا، اینکه چشمان ما باز‌گردد!»"},{"v":34,"t":"پس عیسی ترحم نموده، چشمان ایشان را لمس نمودکه در ساعت بینا گشته، از عقب او روانه شدند."}]},"21":{"fa":[{"v":1,"t":"و چون نزدیک به اورشلیم رسیده، واردبیت‌فاجی نزد کوه زیتون شدند. آنگاه عیسی دو نفر از شاگردان خود را فرستاده،"},{"v":2,"t":"بدیشان گفت: «در این قریه‌ای که پیش روی شمااست بروید و در حال، الاغی با کره‌اش بسته خواهید یافت. آنها را باز کرده، نزد من آورید."},{"v":3,"t":"وهرگاه کسی به شما سخنی گوید، بگویید خداوندبدینها احتیاج دارد که فی الفور آنها را خواهدفرستاد.»"},{"v":4,"t":"و این همه واقع شد تا سخنی که نبی گفته است تمام شود"},{"v":5,"t":"که «دختر صهیون را گوییداینک پادشاه تو نزد تو می‌آید با فروتنی و سواره بر حمار و بر کره الاغ.»"},{"v":6,"t":"پس شاگردان رفته، آنچه عیسی بدیشان امر فرمود، بعمل آوردند"},{"v":7,"t":"و الاغ را با کره آورده، رخت خود را بر آنها انداختند واو بر آنها سوار شد."},{"v":8,"t":"و گروهی بسیار، رختهای خود را در راه گسترانیدند و جمعی از درختان شاخه‌ها بریده، در راه می‌گستردند."},{"v":9,"t":"و جمعی ازپیش و پس او رفته، فریادکنان می‌گفتند: «هوشیعانا پسر داودا، مبارک باد کسی‌که به اسم خداوند می‌آید! هوشیعانا در اعلی علیین!»"},{"v":10,"t":"وچون وارد اورشلیم شد، تمام شهر به آشوب آمده، می‌گفتند: «این کیست؟»"},{"v":11,"t":"آن گروه گفتند: «این است عیسی نبی از ناصره جلیل.»"},{"v":12,"t":"پس عیسی داخل هیکل خدا گشته، جمیع کسانی را که در هیکل خرید و فروش می‌کردند، بیرون نمود و تختهای صرافان و کرسیهای کبوترفروشان را واژگون ساخت."},{"v":13,"t":"و ایشان را گفت: «مکتوب است که خانه من خانه دعا نامیده می‌شود. لیکن شما مغاره دزدانش ساخته‌اید.»"},{"v":14,"t":"و کوران و شلان در هیکل، نزد او آمدند وایشان را شفا بخشید."},{"v":15,"t":"اما روسای کهنه و کاتبان چون عجایبی که از او صادر می‌گشت و کودکان را که در هیکل فریاد برآورده، «هوشیعانا پسر داودا» می‌گفتنددیدند، غضبناک گشته،"},{"v":16,"t":"به وی گفتند: «نمی شنوی آنچه اینها می‌گویند؟» عیسی بدیشان گفت: «بلی مگر نخوانده‌اید این که از دهان کودکان و شیرخوارگان حمد را مهیا ساختی؟»"},{"v":17,"t":"پس ایشان را واگذارده، از شهر بسوی بیت عنیارفته، در آنجا شب را بسر برد."},{"v":18,"t":"بامدادان چون به شهر مراجعت می‌کرد، گرسنه شد."},{"v":19,"t":"و در کناره راه یک درخت انجیر دیده، نزد آن آمد و جز برگ بر آن هیچ نیافت. پس آن را گفت: «از این به بعد میوه تا به ابد بر تونشود!» که در ساعت درخت انجیر خشکید!"},{"v":20,"t":"چون شاگردان´ این را دیدند، متعجب شده، گفتند: «چه بسیار زود درخت انحیر خشک شده است!»"},{"v":21,"t":"عیسی در جواب ایشان گفت: «هرآینه به شما می‌گویم اگر ایمان می‌داشتید و شک نمی نمودید، نه همین را که به درخت انجیر شدمی کردید، بلکه هر گاه بدین کوه می‌گفتید “منتقل شده به دریا افکنده شو” چنین می‌شد."},{"v":22,"t":"و هرآنچه با‌ایمان به دعا طلب کنید، خواهید یافت.»"},{"v":23,"t":"و چون به هیکل درآمده، تعلیم می‌داد، روسای کهنه و مشایخ قوم نزد او آمده، گفتند: «به چه قدرت این اعمال را می‌نمایی و کیست که این قدرت را به تو داده است؟»"},{"v":24,"t":"عیسی در جواب ایشان گفت: «من نیز از شما سخنی می‌پرسم. اگرآن را به من گویید، من هم به شما گویم که این اعمال را به چه قدرت می‌نمایم:"},{"v":25,"t":"تعمید یحیی از کجا بود؟ از آسمان یا از انسان؟» ایشان با خودتفکر کرده، گفتند که «اگر گوییم از آسمان بود، هرآینه گوید پس چرا به وی ایمان نیاوردید."},{"v":26,"t":"واگر گوییم از انسان بود، از مردم می‌ترسیم زیراهمه یحیی را نبی می‌دانند.»"},{"v":27,"t":"پس در جواب عیسی گفتند: «نمی دانیم.» بدیشان گفت: «من هم شما را نمی گویم که به چه قدرت این کارها رامی کنم."},{"v":28,"t":"لیکن چه گمان دارید؟ شخصی را دو پسربود. نزد نخستین آمده، گفت: “ای فرزند امروز به تاکستان من رفته، به‌کار مشغول شو.”"},{"v":29,"t":"درجواب گفت: “نخواهم رفت.” اما بعد پشیمان گشته، برفت."},{"v":30,"t":"و به دومین نیز همچنین گفت. اودر جواب گفت: “ای آقا من می‌روم.” ولی نرفت."},{"v":31,"t":"کدام‌یک از این دو خواهش پدر را به‌جاآورد؟» گفتند: «اولی.» عیسی بدیشان گفت: «هرآینه به شما می‌گویم که باجگیران و فاحشه هاقبل از شما داخل ملکوت خدا می‌گردند،"},{"v":32,"t":"زانرو که یحیی از راه عدالت نزد شما آمد وبدو ایمان نیاوردید، اما باجگیران و فاحشه‌ها بدوایمان آوردند و شما چون دیدید آخر هم پشیمان نشدید تا بدو ایمان آورید."},{"v":33,"t":"و مثلی دیگر بشنوید: صاحب‌خانه‌ای بودکه تاکستانی غرس نموده، خطیره‌ای گردش کشید و چرخشتی در آن کند و برجی بنا نمود. پس آن را به دهقانان سپرده، عازم سفر شد."},{"v":34,"t":"وچون موسم میوه نزدیک شد، غلامان خود را نزددهقانان فرستاد تا میوه های او را بردارند."},{"v":35,"t":"امادهقانان غلامانش را گرفته، بعضی را زدند وبعضی را کشتند و بعضی را سنگسار نمودند."},{"v":36,"t":"باز غلامان دیگر، بیشتر از اولین فرستاده، بدیشان نیز به همانطور سلوک نمودند."},{"v":37,"t":"بالاخره پسر خود را نزد ایشان فرستاده، گفت: “پسر مرا حرمت خواهند داشت.”"},{"v":38,"t":"اما دهقانان چون پسررا دیدند با خود گفتند: “این وارث است. بیایید اورا بکشیم و میراثش را ببریم.”"},{"v":39,"t":"آنگاه او راگرفته، بیرون تاکستان افکنده، کشتند."},{"v":40,"t":"پس چون مالک تاکستان آید، به آن دهقانان چه خواهد کرد؟»"},{"v":41,"t":"گفتند: «البته آن بدکاران را به سختی هلاک خواهد کرد و باغ را به باغبانان دیگرخواهد سپرد که میوه هایش را در موسم بدودهند.»"},{"v":42,"t":"عیسی بدیشان گفت: «مگر در کتب هرگزنخوانده‌اید این که سنگی را که معمارانش ردنمودند، همان سر زاویه شده است. این از جانب خداوند آمد و در نظر ما عجیب است."},{"v":43,"t":"از این جهت شما را می‌گویم که ملکوت خدا از شماگرفته شده، به امتی که میوه‌اش را بیاورند، عطاخواهد شد."},{"v":44,"t":"و هر‌که بر آن سنگ افتد، منکسرشود و اگر آن بر کسی افتد، نرمش سازد.»"},{"v":45,"t":"وچون روسای کهنه و فریسیان مثلهایش راشنیدند، دریافتند که درباره ایشان می‌گوید."},{"v":46,"t":"وچون خواستند او را گرفتار کنند، از مردم ترسیدند زیرا که او را نبی می‌دانستند."}]},"22":{"fa":[{"v":1,"t":"و عیسی توجه نموده، باز به مثلها ایشان را خطاب کرده، گفت:"},{"v":2,"t":"«ملکوت آسمان پادشاهی را ماند که برای پسر خویش عروسی کرد."},{"v":3,"t":"و غلامان خود را فرستاد تا دعوت‌شدگان را به عروسی بخوانند و نخواستند بیایند."},{"v":4,"t":"باز غلامان دیگر روانه نموده، فرمود: “دعوت‌شدگان را بگویید که اینک خوان خود را حاضر ساخته‌ام و گاوان و پرواریهای من کشته شده و همه‌چیز آماده است، به عروسی بیایید.”"},{"v":5,"t":"ولی ایشان بی‌اعتنایی نموده، راه خود را گرفتند، یکی به مزرعه خود و دیگری به تجارت خویش رفت."},{"v":6,"t":"و دیگران غلامان او را گرفته، دشنام داده، کشتند."},{"v":7,"t":"پادشاه چون شنید، غضب نموده، لشکریان خود را فرستاده، آن قاتلان را به قتل رسانید و شهر ایشان را بسوخت."},{"v":8,"t":"آنگاه غلامان خود را فرمود: “عروسی حاضر است؛ لیکن دعوت‌شدگان لیاقت نداشتند."},{"v":9,"t":"الان به شوارع عامه بروید و هر‌که را بیابید به عروسی بطلبید.”"},{"v":10,"t":"پس آن غلامان به‌سر راهها رفته، نیک و بد هرکه را یافتند جمع کردند، چنانکه خانه عروسی ازمجلسیان مملو گشت."},{"v":11,"t":"آنگاه پادشاه بجهت دیدن اهل مجلس داخل شده، شخصی را درآنجا دید که جامه عروسی در بر ندارد."},{"v":12,"t":"بدوگفت: “ای عزیز چطور در اینجا آمدی و حال آنکه جامه عروسی در بر نداری؟” او خاموش شد."},{"v":13,"t":"آنگاه پادشاه خادمان خود را فرمود: “این شخص را دست و پا بسته بردارید و در ظلمت خارجی اندازید، جایی که گریه و فشار دندان باشد.”"},{"v":14,"t":"زیرا طلبیدگان بسیارند و برگزیدگان کم.»"},{"v":15,"t":"پس فریسیان رفته، شورا نمودند که چطوراو را در گفتگو گرفتار سازند."},{"v":16,"t":"و شاگردان خودرا با هیرودیان نزد وی فرستاده، گفتند: «استادامی دانیم که صادق هستی و طریق خدا را به راستی تعلیم می‌نمایی و از کسی باک نداری زیراکه به ظاهر خلق نمی نگری."},{"v":17,"t":"پس به ما بگو رای تو چیست. آیا جزیه دادن به قیصر رواست یا نه؟»"},{"v":18,"t":"عیسی شرارت ایشان را درک کرده، گفت: «ای ریاکاران، چرا مرا تجربه می‌کنید؟"},{"v":19,"t":"سکه جزیه را به من بنمایید.» ایشان دیناری نزد وی آوردند."},{"v":20,"t":"بدیشان گفت: «این صورت و رقم از آن کیست؟»"},{"v":21,"t":"بدو گفتند: «از آن قیصر.» بدیشان گفت: «مال قیصر را به قیصر ادا کنید و مال خدا رابه خدا!»"},{"v":22,"t":"چون ایشان شنیدند، متعجب شدندو او را واگذارده، برفتند."},{"v":23,"t":"و در همان روز، صدوقیان که منکر قیامت هستند نزد او آمده، سوال نموده،"},{"v":24,"t":"گفتند: «ای استاد، موسی گفت اگر کسی بی‌اولاد بمیرد، می‌باید برادرش زن او را نکاح کند تا نسلی برای برادر خود پیدا نماید."},{"v":25,"t":"باری در میان ما هفت برادر بودند که اول زنی گرفته، بمرد و چون اولادی نداشت زن را به برادر خود ترک کرد."},{"v":26,"t":"وهمچنین دومین و سومین تا هفتمین."},{"v":27,"t":"و آخر ازهمه آن زن نیز مرد."},{"v":28,"t":"پس او در قیامت، زن کدام‌یک از آن هفت خواهد بود زیرا که همه او راداشتند؟»"},{"v":29,"t":"عیسی در جواب ایشان گفت: «گمراه هستید از این‌رو که کتاب و قوت خدا رادر نیافته‌اید،"},{"v":30,"t":"زیرا که در قیامت، نه نکاح می‌کنند و نه نکاح کرده می‌شوند بلکه مثل ملائکه خدا در آسمان می‌باشند."},{"v":31,"t":"اما درباره قیامت مردگان، آیا نخوانده‌اید کلامی را که خدا به شما گفته است،"},{"v":32,"t":"من هستم خدای ابراهیم و خدای اسحاق و خدای یعقوب؟ خدا، خدای مردگان نیست بلکه خدای زندگان است.»"},{"v":33,"t":"و آن گروه چون شنیدند، از تعلیم وی متحیر شدند."},{"v":34,"t":"اما چون فریسیان شنیدند که صدوقیان را مجاب نموده است، با هم جمع شدند."},{"v":35,"t":"و یکی از ایشان که فقیه بود، از وی به طریق امتحان سوال کرده، گفت:"},{"v":36,"t":"«ای استاد، کدام حکم در شریعت بزرگتر است؟»"},{"v":37,"t":"عیسی وی را گفت: «اینکه خداوند خدای خود را به همه دل و تمامی نفس و تمامی فکر خود محبت نما."},{"v":38,"t":"این است حکم اول و اعظم."},{"v":39,"t":"و دوم مثل آن است یعنی همسایه خود را مثل خود محبت نما."},{"v":40,"t":"بدین دو حکم، تمام تورات و صحف انبیامتعلق است.»"},{"v":41,"t":"و چون فریسیان جمع بودند، عیسی ازایشان پرسیده،"},{"v":42,"t":"گفت: «درباره مسیح چه گمان می‌برید؟ او پسر کیست؟» بدو گفتند: «پسر داود.»"},{"v":43,"t":"ایشان را گفت: «پس چطور داود در روح، او راخداوند می‌خواند؟ چنانکه می‌گوید:"},{"v":44,"t":"“خداوندبه خداوند من گفت، به‌دست راست من بنشین تادشمانان تو را پای انداز تو سازم.”"},{"v":45,"t":"پس هرگاه داود او را خداوند می‌خواند، چگونه پسرش می‌باشد؟»"},{"v":46,"t":"و هیچ‌کس قدرت جواب وی هرگز نداشت و نه کسی از آن روز دیگرجرات سوال کردن از او نمود."}]},"23":{"fa":[{"v":1,"t":"آنگاه عیسی آن جماعت و شاگردان خود را خطاب کرده،"},{"v":2,"t":"گفت: «کاتبان وفریسیان بر کرسی موسی نشسته‌اند."},{"v":3,"t":"پس آنچه به شما گویند، نگاه دارید و به‌جا آورید، لیکن مثل اعمال ایشان مکنید زیرا می‌گویند ونمی کنند."},{"v":4,"t":"زیرا بارهای گران و دشوار رامی بندند و بر دوش مردم می‌نهند و خودنمی خواهند آنها را به یک انگشت حرکت دهند."},{"v":5,"t":"و همه کارهای خود را می‌کنند تا مردم، ایشان را ببینند. حمایلهای خود را عریض و دامنهای قبای خود را پهن می‌سازند،"},{"v":6,"t":"و بالا نشستن درضیافتها و کرسیهای صدر در کنایس را دوست می‌دارند،"},{"v":7,"t":"و تعظیم در کوچه‌ها را و اینکه مردم ایشان را آقا آقا بخوانند."},{"v":8,"t":"لیکن شماآقا خوانده مشوید، زیرا استاد شما یکی است یعنی مسیح و جمیع شما برادرانید."},{"v":9,"t":"و هیچ‌کس را بر زمین، پدر خود مخوانید زیرا پدر شمایکی است که در آسمان است."},{"v":10,"t":"و پیشواخوانده مشوید، زیرا پیشوای شما یکی است یعنی مسیح."},{"v":11,"t":"و هر‌که از شما بزرگتر باشد، خادم شما بود."},{"v":12,"t":"و هر‌که خود را بلند کند، پست گردد و هر‌که خود را فروتن سازد سرافرازگردد."},{"v":13,"t":"وای بر شما‌ای کاتبان و فریسیان ریاکار که در ملکوت آسمان را به روی مردم می‌بندید، زیراخود داخل آن نمی شوید و داخل‌شوندگان را ازدخول مانع می‌شوید."},{"v":14,"t":"وای بر شما‌ای کاتبان وفریسیان ریاکار، زیرا خانه های بیوه‌زنان رامی بلعید و از روی ریا نماز را طویل می‌کنید؛ ازآنرو عذاب شدیدتر خواهید یافت."},{"v":15,"t":"وای برشما‌ای کاتبان و فریسیان ریاکار، زیرا که بر و بحررا می‌گردید تا مریدی پیدا کنید و چون پیدا شداو را دو مرتبه پست‌تر از خود، پسر جهنم می‌سازید!"},{"v":16,"t":"وای بر شما‌ای راهنمایان کور که می‌گویید “هر‌که به هیکل قسم خورد باکی نیست لیکن هر‌که به طلای هیکل قسم خورد باید وفاکند.”"},{"v":17,"t":"‌ای نادانان و نابینایان، آیا کدام افضل است؟ طلا یا هیکلی که طلا را مقدس می‌سازد؟"},{"v":18,"t":"“و هر‌که به مذبح قسم خورد باکی نیست لیکن هر‌که به هدیه‌ای که بر آن است قسم خورد، بایدادا کند.”"},{"v":19,"t":"‌ای جهال و کوران، کدام افضل است؟ هدیه یا مذبح که هدیه را تقدیس می‌نماید؟"},{"v":20,"t":"پس هر‌که به مذبح قسم خورد، به آن و به هرچه بر آن است قسم خورده است؛"},{"v":21,"t":"و هر‌که به هیکل قسم خورد، به آن و به او که در آن ساکن است، قسم خورده است؛"},{"v":22,"t":"و هر‌که به آسمان قسم خورد، به کرسی خدا و به او که بر آن نشسته است، قسم خورده باشد."},{"v":23,"t":"وای بر شما‌ای کاتبان و فریسیان ریاکار که نعناع و شبت و زیره را عشر می‌دهید و اعظم احکام شریعت، یعنی عدالت و رحمت و ایمان را ترک کرده‌اید! می‌بایست آنها را به‌جا آورده، اینها را نیز ترک نکرده باشید."},{"v":24,"t":"‌ای رهنمایان کورکه پشه را صافی می‌کنید و شتر را فرو می‌برید!"},{"v":25,"t":"وای بر شما‌ای کاتبان و فریسیان ریاکار، از آن رو که بیرون پیاله و بشقاب را پاک می‌نمایید ودرون آنها مملو از جبر و ظلم است."},{"v":26,"t":"‌ای فریسی کور، اول درون پیاله و بشقاب را طاهرساز تا بیرونش نیز طاهر شود!"},{"v":27,"t":"وای بر شما‌ای کاتبان و فریسیان ریاکار که چون قبور سفید شده می‌باشید که از بیرون، نیکو می‌نماید لیکن درون آنها از استخوانهای مردگان و سایر نجاسات پراست!"},{"v":28,"t":"همچنین شما نیز ظاهر به مردم عادل می‌نمایید، لیکن باطن از ریاکاری و شرارت مملوهستید."},{"v":29,"t":"وای بر شما‌ای کاتبان و فریسیان ریاکار که قبرهای انبیا را بنا می‌کنید و مدفنهای صادقان رازینت می‌دهید،"},{"v":30,"t":"و می‌گویید: “اگر در ایام پدران خود می‌بودیم، در ریختن خون انبیا با ایشان شریک نمی شدیم!”"},{"v":31,"t":"پس بر خود شهادت می‌دهید که فرزندان قاتلان انبیا هستید."},{"v":32,"t":"پس شما پیمانه پدران خود را لبریز کنید!"},{"v":33,"t":"‌ای ماران و افعی‌زادگان! چگونه از عذاب جهنم فرارخواهید کرد؟"},{"v":34,"t":"لهذا الحال انبیا و حکماء وکاتبان نزد شما می‌فرستم و بعضی را خواهیدکشت و به دار خواهید کشید و بعضی را درکنایس خود تازیانه زده، از شهر به شهر خواهیدراند،"},{"v":35,"t":"تا همه خونهای صادقان که بر زمین ریخته شد بر شما وارد آید، از خون هابیل صدیق تا خون زکریا ابن برخیا که او را در میان هیکل ومذبح کشتید."},{"v":36,"t":"هرآینه به شما می‌گویم که این همه بر این طایفه خواهد آمد!"},{"v":37,"t":"«ای اورشلیم، اورشلیم، قاتل انبیا وسنگسار کننده مرسلان خود! چند مرتبه‌خواستم فرزندان تو را جمع کنم، مثل مرغی که جوجه های خود را زیر بال خود جمع می‌کند ونخواستید!"},{"v":38,"t":"اینک خانه شما برای شما ویران گذارده می‌شود."},{"v":39,"t":"زیرا به شما می‌گویم از این پس مرا نخواهید دید تا بگویید مبارک است او که به نام خداوند می‌آید.»"}]},"24":{"fa":[{"v":1,"t":"پس عیسی از هیکل بیرون شده، برفت. و شاگردانش پیش آمدند تا عمارتهای هیکل را بدو نشان دهند."},{"v":2,"t":"عیسی ایشان را گفت: «آیا همه این چیزها را نمی بینید؟ هرآینه به شمامی گویم در اینجا سنگی بر سنگی گذارده نخواهد شد که به زیر افکنده نشود!»"},{"v":3,"t":"و چون به کوه زیتون نشسته بود، شاگردانش در خلوت نزدوی آمده، گفتند: «به ما بگو که این امور کی واقع می‌شود و نشان آمدن تو و انقضای عالم چیست.»"},{"v":4,"t":"عیسی در جواب ایشان گفت: «زنهار کسی شما را گمراه نکند!"},{"v":5,"t":"زآنرو که بسا به نام من آمده خواهند گفت که من مسیح هستم و بسیاری را گمراه خواهند کرد."},{"v":6,"t":"و جنگها و اخبار جنگها راخواهید شنید. زنهار مضطرب مشوید زیرا که وقوع این همه لازم است، لیکن انتها هنوز نیست."},{"v":7,"t":"زیرا قومی با قومی و مملکتی با مملکتی مقاومت خواهند نمود و قحطیها و وباها وزلزله‌ها در جایها پدید آید."},{"v":8,"t":"اما همه اینها آغازدردهای زه است."},{"v":9,"t":"آنگاه شما را به مصیبت سپرده، خواهند کشت و جمیع امت‌ها بجهت اسم من از شما نفرت کنند."},{"v":10,"t":"و در آن زمان، بسیاری لغزش خورده، یکدیگر را تسلیم کنند واز یکدیگر نفرت گیرند."},{"v":11,"t":"و بسا انبیای کذبه ظاهر شده، بسیاری را گمراه کنند."},{"v":12,"t":"و بجهت افزونی گناه محبت بسیاری سرد خواهد شد."},{"v":13,"t":"لیکن هر‌که تا به انتها صبر کند، نجات یابد."},{"v":14,"t":"و به این بشارت ملکوت در تمام عالم موعظه خواهد شد تا بر جمیع امت‌ها شهادتی شود؛ آنگاه انتها خواهد رسید."},{"v":15,"t":"«پس چون مکروه ویرانی را که به زبان دانیال نبی گفته شده است، در مقام مقدس بر پاشده بینید هر‌که خواند دریافت کند"},{"v":16,"t":"آنگاه هر‌که در یهودیه باشد به کوهستان بگریزد؛"},{"v":17,"t":"وهر‌که بر بام باشد، بجهت برداشتن چیزی از خانه به زیر نیاید؛"},{"v":18,"t":"و هر‌که در مزرعه است، بجهت برداشتن رخت خود برنگردد."},{"v":19,"t":"لیکن وای برآبستنان و شیر دهندگان در آن ایام!"},{"v":20,"t":"پس دعاکنید تا فرار شما در زمستان یا در سبت نشود،"},{"v":21,"t":"زیرا که در آن زمان چنان مصیبت عظیمی ظاهر می‌شود که از ابتدا عالم تا کنون نشده ونخواهد شد!"},{"v":22,"t":"و اگر آن ایام کوتاه نشدی، هیچ بشری نجات نیافتی، لیکن بخاطر برگزیدگان، آن روزها کوتاه خواهد شد."},{"v":23,"t":"آنگاه اگر کسی به شما گوید: “اینک مسیح در اینجا یا در آنجا است “ باور مکنید،"},{"v":24,"t":"زیرا که مسیحیان کاذب و انبیا کذبه ظاهر شده، علامات ومعجزات عظیمه چنان خواهند نمود که اگرممکن بودی برگزیدگان را نیز گمراه کردندی."},{"v":25,"t":"اینک شما را پیش خبر دادم."},{"v":26,"t":"«پس اگر شما را گویند: اینک درصحراست، بیرون مروید یا آنکه در خلوت است، باور مکنید،"},{"v":27,"t":"زیرا همچنان‌که برق ازمشرق ساطع شده، تا به مغرب ظاهر می‌شود، ظهور پسر انسان نیز چنین خواهد شد."},{"v":28,"t":"و هرجا که مرداری باشد، کرکسان در آنجا جمع شوند."},{"v":29,"t":"و فور بعد از مصیبت آن ایام، آفتاب تاریک گردد و ماه نور خود را ندهد و ستارگان ازآسمان فرو ریزند و قوتهای افلاک متزلزل گردد."},{"v":30,"t":"آنگاه علامت پسر انسان در آسمان پدید گرددو در آن وقت، جمیع طوایف زمین سینه زنی کنندو پسر انسان را بینند که بر ابرهای آسمان، با قوت و جلال عظیم می‌آید؛"},{"v":31,"t":"و فرشتگان خود را باصور بلند آواز فرستاده، برگزیدگان او را ازبادهای اربعه از کران تا بکران فلک فراهم خواهندآورد."},{"v":32,"t":"«پس از درخت انجیر مثلش را فرا‌گیرید که چون شاخه‌اش نازک شده، برگها می‌آورد، می فهمید که تابستان نزدیک است."},{"v":33,"t":"همچنین شما نیز چون این همه را بینید، بفهمید که نزدیک بلکه بر در است."},{"v":34,"t":"هرآینه به شما می‌گویم تا این همه واقع نشود، این طایفه نخواهد گذشت."},{"v":35,"t":"آسمان و زمین زایل خواهد شد، لیکن سخنان من هرگز زایل نخواهد شد."},{"v":36,"t":"«اما از آن روز و ساعت هیچ‌کس اطلاع ندارد، حتی ملائکه آسمان جز پدر من و بس."},{"v":37,"t":"لیکن چنانکه ایام نوح بود، ظهور پسر انسان نیزچنان خواهد بود."},{"v":38,"t":"زیرا همچنان‌که در ایام قبل از طوفان می‌خوردند و می‌آشامیدند و نکاح می‌کردند و منکوحه می‌شدند تا روزی که نوح داخل کشتی گشت،"},{"v":39,"t":"و نفهمیدند تا طوفان آمده، همه را ببرد، همچنین ظهور پسر انسان نیزخواهد بود."},{"v":40,"t":"آنگاه دو نفری که در مزرعه‌ای می‌باشند، یکی گرفته و دیگری واگذارده شود."},{"v":41,"t":"و دو زن که دستاس می‌کنند، یکی گرفته ودیگری رها شود."},{"v":42,"t":"پس بیدار باشید زیرا که نمی دانید در کدام ساعت خداوند شما می‌آید."},{"v":43,"t":"لیکن این را بدانید که اگر صاحب‌خانه می‌دانست در چه پاس از شب دزد می‌آید، بیدارمی ماند و نمی گذاشت که به خانه‌اش نقب زند."},{"v":44,"t":"لهذا شما نیز حاضر باشید، زیرا در ساعتی که گمان نبرید، پسر انسان می‌آید."},{"v":45,"t":"«پس آن غلام امین و دانا کیست که آقایش او را بر اهل خانه خود بگمارد تا ایشان را در وقت معین خوراک دهد؟"},{"v":46,"t":"خوشابحال آن غلامی که چون آقایش آید، او را در چنین کار مشغول یابد."},{"v":47,"t":"هرآینه به شما می‌گویم که او را بر تمام مایملک خود خواهد گماشت."},{"v":48,"t":"لیکن هرگاه آن غلام شریر با خود گوید که آقای من در‌آمدن تاخیر می‌نماید،"},{"v":49,"t":"و شروع کند به زدن همقطاران خود و خوردن و نوشیدن با میگساران،"},{"v":50,"t":"هرآینه آقای آن غلام آید، در روزی که منتظرنباشد و در ساعتی که نداند،"},{"v":51,"t":"و او را دو پاره کرده، نصیبش را با ریاکاران قرار دهد در مکانی که گریه و فشار دندان خواهد بود."}]},"25":{"fa":[{"v":1,"t":"«در آن زمان ملکوت آسمان مثل ده باکره خواهد بود که مشعلهای خود رابرداشته، به استقبال داماد بیرون رفتند."},{"v":2,"t":"و ازایشان پنج دانا و پنج نادان بودند."},{"v":3,"t":"اما نادانان مشعلهای خود را برداشته، هیچ روغن با خودنبردند."},{"v":4,"t":"لیکن دانایان، روغن در ظروف خود بامشعلهای خویش برداشتند."},{"v":5,"t":"و چون آمدن دامادبطول انجامید، همه پینکی زده، خفتند."},{"v":6,"t":"و درنصف شب صدایی بلند شد که “اینک دامادمی آید به استقبال وی بشتابید.”"},{"v":7,"t":"پس تمامی آن باکره‌ها برخاسته، مشعلهای خود را اصلاح نمودند."},{"v":8,"t":"و نادانان، دانایان را گفتند: “از روغن خود به ما دهید زیرا مشعلهای ما خاموش می‌شود.”"},{"v":9,"t":"اما دانایان در جواب گفتند: “نمی شود، مبادا ما و شما را کفاف ندهد. بلکه نزدفروشندگان رفته، برای خود بخرید.”"},{"v":10,"t":"و درحینی که ایشان بجهت خرید می‌رفتند، داماد برسید و آنانی که حاضر بودند، با وی به عروسی داخل شده، در بسته گردید."},{"v":11,"t":"بعد از آن، باکره های دیگر نیز آمده، گفتند: “خداوندا برای ماباز کن.”"},{"v":12,"t":"او در جواب گفت: “هرآینه به شمامی گویم شما را نمی شناسم.”"},{"v":13,"t":"پس بیدار باشیدزیرا که آن روز و ساعت را نمی دانید."},{"v":14,"t":"«زیرا چنانکه مردی عازم سفر شده، غلامان خود را طلبید و اموال خود را بدیشان سپرد،"},{"v":15,"t":"یکی را پنج قنطار و دیگری را دو وسومی را یک داد؛ هر یک را بحسب استعدادش. و بی‌درنگ متوجه سفر شد."},{"v":16,"t":"پس آنکه پنج قنطار یافته بود، رفته و با آنها تجارت نموده، پنج قنطار دیگر سود کرد."},{"v":17,"t":"و همچنین صاحب دوقنطار نیز دو قنطار دیگر سود گرفت."},{"v":18,"t":"اما آنکه یک قنطار گرفته بود، رفته زمین را کند و نقد آقای خود را پنهان نمود."},{"v":19,"t":"«و بعد از مدت مدیدی، آقای آن غلامان آمده، از ایشان حساب خواست."},{"v":20,"t":"پس آنکه پنج قنطار یافته بود، پیش آمده، پنج قنطار دیگرآورده، گفت: خداوندا پنج قنطار به من سپردی، اینک پنج قنطار دیگر سود کردم.”"},{"v":21,"t":"آقای او به وی گفت: آفرین‌ای غلام نیک متدین! بر چیزهای اندک امین بودی، تو را بر چیزهای بسیار خواهم گماشت. به شادی خداوند خود داخل شو!"},{"v":22,"t":"وصاحب دو قنطار نیز آمده، گفت: ای آقا دو قنطارتسلیم من نمودی، اینک دو قنطار دیگر سودیافته‌ام."},{"v":23,"t":"آقایش وی را گفت: آفرین‌ای غلام نیک متدین! بر چیزهای کم امین بودی، تو را بر چیزهای بسیار می‌گمارم. در خوشی خداوندخود داخل شو!"},{"v":24,"t":"پس آنکه یک قنطار گرفته بود، پیش آمده، گفت: ای آقا چون تو رامی شناختم که مرد درشت خویی می‌باشی، ازجایی که نکاشته‌ای می‌دروی و از جایی که نیفشانده‌ای جمع می‌کنی،"},{"v":25,"t":"پس ترسان شده، رفتم و قنطار تو را زیر زمین نهفتم. اینک مال توموجود است."},{"v":26,"t":"آقایش در جواب وی گفت: ای غلام شریر بیکاره! دانسته‌ای که از جایی که نکاشته‌ام میدروم و از مکانی که نپاشیده‌ام، جمع می‌کنم."},{"v":27,"t":"از همین جهت تو را می‌بایست نقد مرابه صرافان بدهی تا وقتی که بیایم مال خود را باسود بیابم."},{"v":28,"t":"الحال آن قنطار را از او گرفته، به صاحب ده قنطار بدهید."},{"v":29,"t":"زیرا به هر‌که داردداده شود و افزونی یابد و از آنکه ندارد آنچه داردنیز گرفته شود."},{"v":30,"t":"و آن غلام بی‌نفع را در ظلمت خارجی اندازید، جایی که گریه و فشار دندان خواهد بود."},{"v":31,"t":"«اما چون پسر انسان در جلال خود باجمیع ملائکه مقدس خویش آید، آنگاه بر کرسی جلال خود خواهد نشست،"},{"v":32,"t":"و جمیع امت‌ها درحضور او جمع شوند و آنها را از همدیگر جدامی کند به قسمی که شبان میشها را از بزها جدامی کند."},{"v":33,"t":"و میشها را بر دست راست و بزها را برچپ خود قرار دهد."},{"v":34,"t":"آنگاه پادشاه به اصحاب طرف راست گوید: بیایید‌ای برکت یافتگان از پدر من و ملکوتی را که از ابتدای عالم برای شما آماده‌شده است، به میراث گیرید."},{"v":35,"t":"زیرا چون گرسنه بودم مرا طعام دادید، تشنه بودم سیرآبم نمودید، غریب بودم مرا جا دادید،"},{"v":36,"t":"عریان بودم مراپوشانیدید، مریض بودم عیادتم کردید، در حبس بودم دیدن من آمدید."},{"v":37,"t":"آنگاه عادلان به پاسخ گویند: ای خداوند، کی گرسنه ات دیدیم تاطعامت دهیم، یا تشنه ات یافتیم تا سیرآبت نماییم،"},{"v":38,"t":"یا کی تو را غریب یافتیم تا تو را جادهیم یا عریان تا بپوشانیم،"},{"v":39,"t":"و کی تو را مریض یامحبوس یافتیم تا عیادتت کنیم؟"},{"v":40,"t":"پادشاه درجواب ایشان گوید: هرآینه به شما می‌گویم، آنچه به یکی از این برادران کوچکترین من کردید، به من کرده‌اید."},{"v":41,"t":"«پس اصحاب طرف چپ را گوید: ای ملعونان، از من دور شوید در آتش جاودانی که برای ابلیس و فرشتگان او مهیا شده است."},{"v":42,"t":"زیراگرسنه بودم مرا خوراک ندادید، تشنه بودم مراآب ندادید،"},{"v":43,"t":"غریب بودم مرا جا ندادید، عریان بودم مرا نپوشانیدید، مریض و محبوس بودم عیادتم ننمودید."},{"v":44,"t":"پس ایشان نیز به پاسخ گویند: ای خداوند، کی تو را گرسنه یا تشنه یاغریب یا برهنه یا مریض یا محبوس دیده، خدمتت نکردیم؟"},{"v":45,"t":"آنگاه در جواب ایشان گوید: هرآینه به شما می‌گویم، آنچه به یکی از این کوچکان نکردید، به من نکرده‌اید."},{"v":46,"t":"و ایشان درعذاب جاودانی خواهند رفت، اما عادلان درحیات جاودانی.»"}]},"26":{"fa":[{"v":1,"t":"و چون عیسی همه این سخنان را به اتمام رسانید، به شاگردان خود گفت:"},{"v":2,"t":"«می‌دانید که بعد از دو روز عید فصح است که پسر انسان تسلیم کرده می‌شود تا مصلوب گردد.»"},{"v":3,"t":"آنگاه روسای کهنه و کاتبان و مشایخ قوم دردیوانخانه رئیس کهنه که قیافا نام داشت جمع شده،"},{"v":4,"t":"شورا نمودند تا عیسی را به حیله گرفتارساخته، به قتل رسانند."},{"v":5,"t":"اما گفتند: «نه در وقت عید مبادا آشوبی در قوم بر پا شود.»"},{"v":6,"t":"و هنگامی که عیسی در بیت عنیا در خانه شمعون ابرص شد،"},{"v":7,"t":"زنی با شیشه‌ای عطر گرانبهانزد او آمده، چون بنشست بر سر وی ریخت."},{"v":8,"t":"اماشاگردانش چون این را دیدند، غضب نموده، گفتند: «چرا این اسراف شده است؟"},{"v":9,"t":"زیرا ممکن بود این عطر به قیمت گران فروخته و به فقرا داده شود.»"},{"v":10,"t":"عیسی این را درک کرده، بدیشان گفت: «چرا بدین زن زحمت می‌دهید؟ زیرا کار نیکو به من کرده است."},{"v":11,"t":"زیرا که فقرا را همیشه نزد خوددارید اما مرا همیشه ندارید."},{"v":12,"t":"و این زن که این عطر را بر بدنم مالید، بجهت دفن من کرده است."},{"v":13,"t":"هرآینه به شما می‌گویم هر جایی که درتمام عالم بدین بشارت موعظه کرده شود، کاراین زن نیز بجهت یادگاری او مذکور خواهدشد.»"},{"v":14,"t":"«آنگاه یکی از آن دوازده که به یهودای اسخریوطی مسمی بود، نزد روسای کهنه رفته،"},{"v":15,"t":"گفت: «مرا چند خواهید داد تا او را به شماتسلیم کنم؟ «ایشان سی پاره نقره با وی قراردادند."},{"v":16,"t":"و از آن وقت در صدد فرصت شد تا اورا بدیشان تسلیم کند."},{"v":17,"t":"پس در روز اول عید فطیر، شاگردان نزدعیسی آمده، گفتند: «کجا می‌خواهی فصح راآماده کنیم تا بخوری؟»"},{"v":18,"t":"گفت: «به شهر، نزدفلان کس رفته، بدو گویید: “استاد می‌گوید وقت من نزدیک شد و فصح را در خانه تو با شاگردان خود صرف می‌نمایم.”»"},{"v":19,"t":"شاگردان چنانکه عیسی ایشان را امر فرمود کردند و فصح را مهیاساختند."},{"v":20,"t":"چون وقت شام رسید با آن دوازده بنشست."},{"v":21,"t":"و وقتی که ایشان غذا می‌خوردند، اوگفت: «هرآینه به شما می‌گویم که یکی از شما مراتسلیم می‌کند!»"},{"v":22,"t":"پس بغایت غمگین شده، هریک از ایشان به وی سخن آغاز کردند که «خداوندا آیا من آنم؟»"},{"v":23,"t":"او در جواب گفت: «آنکه دست با من در قاب فرو برد، همان کس مرا تسلیم نماید!"},{"v":24,"t":"هرآینه پسر انسان به همانطور که درباره او مکتوب است رحلت می‌کند. لیکن وای بر آنکسی‌که پسر انسان بدست او تسلیم شود! آن شخص را بهتر بودی که تولد نیافتی!»"},{"v":25,"t":"و یهوداکه تسلیم‌کننده وی بود، به جواب گفت: «ای استاد آیا من آنم؟» به وی گفت: «تو خود گفتی!»"},{"v":26,"t":"و چون ایشان غذا می‌خوردند، عیسی نان راگرفته، برکت داد و پاره کرده، به شاگردان داد وگفت: «بگیرید و بخورید، این است بدن من.»"},{"v":27,"t":"وپیاله را گرفته، شکر نمود و بدیشان داده، گفت: «همه شما از این بنوشید،"},{"v":28,"t":"زیرا که این است خون من در عهد جدید که در راه بسیاری بجهت آمرزش گناهان ریخته می‌شود."},{"v":29,"t":"اما به شمامی گویم که بعد از این از میوه مو دیگر نخواهم نوشید تا روزی که آن را با شما در ملکوت پدرخود، تازه آشامم.»"},{"v":30,"t":"پس تسبیح خواندند و به سوی کوه زیتون روانه شدند."},{"v":31,"t":"آنگاه عیسی بدیشان گفت: «همه شما امشب درباره من لغزش می‌خورید چنانکه مکتوب است که شبان را می‌زنم و گوسفندان گله پراکنده می‌شوند."},{"v":32,"t":"لیکن بعد از برخاستنم، پیش از شما به جلیل خواهم رفت.»"},{"v":33,"t":"پطرس درجواب وی گفت: «هر گاه همه درباره تو لغزش خورند، من هرگز نخورم.»"},{"v":34,"t":"عیسی به وی گفت: «هرآینه به تو می‌گویم که در همین شب قبل ازبانک زدن خروس، سه مرتبه مرا انکار خواهی کرد!»"},{"v":35,"t":"پطرس به وی گفت: «هرگاه مردنم با تو لازم شود، هرگز تو را انکار نکنم!» و سایرشاگردان نیز همچنان گفتند."},{"v":36,"t":"آنگاه عیسی با ایشان به موضعی که مسمی به جتسیمانی بود رسیده، به شاگردان خود گفت: «در اینجا بنشینید تا من رفته، در آنجا دعا کنم.»"},{"v":37,"t":"و پطرس و دو پسر زبدی را برداشته، بی‌نهایت غمگین و دردناک شد."},{"v":38,"t":"پس بدیشان گفت: «نفس من از غایت الم مشرف به موت شده است. در اینجا مانده با من بیدار باشید.»"},{"v":39,"t":"پس قدری پیش رفته، به روی در‌افتاد و دعا کرده، گفت: «ای پدر من، اگر ممکن باشد این پیاله از من بگذرد؛ لیکن نه به خواهش من، بلکه به اراداه تو.»"},{"v":40,"t":"و نزدشاگردان خود آمده، ایشان را در خواب یافت. وبه پطرس گفت: «آیا همچنین نمی توانستید یک ساعت با من بیدار باشید؟"},{"v":41,"t":"بیدار باشید و دعاکنید تا در معرض آزمایش نیفتید! روح راغب است، لیکن جسم ناتوان.»"},{"v":42,"t":"و بار دیگر رفته، بازدعا نموده، گفت: «ای پدر من، اگر ممکن نباشد که این پیاله بدون نوشیدن از من بگذرد، آنچه اراده تواست بشود.»"},{"v":43,"t":"و آمده، باز ایشان را در خواب یافت زیرا که چشمان ایشان سنگین شده بود."},{"v":44,"t":"پس ایشان را ترک کرده، رفت و دفعه سوم به همان کلام دعا کرد."},{"v":45,"t":"آنگاه نزد شاگردان آمده، بدیشان گفت: «مابقی را بخوابید واستراحت کنید. الحال ساعت رسیده است که پسر انسان به‌دست گناهکاران تسلیم شود."},{"v":46,"t":"برخیزید برویم. اینک تسلیم‌کننده من نزدیک است!»"},{"v":47,"t":"و هنوز سخن می‌گفت که ناگاه یهودا که یکی از آن دوازده بود با جمعی کثیر با شمشیرهاو چوبها از جانب روساء کهنه و مشایخ قوم آمدند."},{"v":48,"t":"و تسلیم‌کننده او بدیشان نشانی داده، گفته بود: «هر‌که را بوسه زنم، همان است. او رامحکم بگیرید.»"},{"v":49,"t":"در ساعت نزد عیسی آمده، گفت: «سلام یا سیدی!» و او را بوسید."},{"v":50,"t":"عیسی وی را گفت: «ای رفیق، از بهر‌چه آمدی؟» آنگاه پیش آمده، دست بر عیسی انداخته، او را گرفتند."},{"v":51,"t":"و ناگاه یکی از همراهان عیسی دست آورده، شمشیر خود را از غلاف کشیده، بر غلام رئیس کهنه زد و گوشش را از تن جدا کرد."},{"v":52,"t":"آنگاه عیسی وی را گفت: «شمشیر خود را غلاف کن، زیرا هر‌که شمشیر گیرد، به شمشیر هلاک گردد."},{"v":53,"t":"آیا گمان می‌بری که نمی توانم الحال از پدرخود درخواست کنم که زیاده از دوازده فوج ازملائکه برای من حاضر سازد؟"},{"v":54,"t":"لیکن در این صورت کتب چگونه تمام گردد که همچنین می‌بایست بشود؟»"},{"v":55,"t":"در آن ساعت، به آن گروه گفت: گویا بر دزد بجهت گرفتن من با تیغها وچوبها بیرون آمدید! هر روز با شما در هیکل نشسته، تعلیم می‌دادم و مرا نگرفتید."},{"v":56,"t":"لیکن این همه شد تا کتب انبیا تمام شود.» در آن وقت جمیع شاگردان او را واگذارده، بگریختند."},{"v":57,"t":"و آنانی که عیسی را گرفته بودند، او را نزدقیافا رئیس کهنه جایی که کاتبان و مشایخ جمع بودند، بردند."},{"v":58,"t":"اما پطرس از دور در عقب اوآمده، به خانه رئیس کهنه در‌آمد و با خادمان بنشست تا انجام کار را ببیند."},{"v":59,"t":"پس روسای کهنه و مشایخ و تمامی اهل شورا طلب شهادت دروغ بر عیسی می‌کردند تا او را بقتل رسانند،"},{"v":60,"t":"لیکن نیافتند. با آنکه چند شاهد دروغ پیش آمدند، هیچ نیافتند. آخر دو نفر آمده،"},{"v":61,"t":"گفتند: «این شخص گفت: “می توانم هیکل خدا را خراب کنم و در سه روزش بنا نمایم.”»"},{"v":62,"t":"پس رئیس کهنه برخاسته، بدو گفت: «هیچ جواب نمی دهی؟ چیست که اینها بر تو شهادت می‌دهند؟»"},{"v":63,"t":"اما عیسی خاموش ماند! تا آنکه رئیس کهنه روی به وی کرده، گفت: «تو را به خدای حی قسم می‌دهم مارا بگوی که تو مسیح پس خدا هستی یا نه؟»"},{"v":64,"t":"عیسی به وی گفت: «تو گفتی! و نیز شما رامی گویم بعد از این پسر انسان را خواهید دید که بر دست راست قوت نشسته، بر ابرهای آسمان می‌آید!»"},{"v":65,"t":"در ساعت رئیس کهنه رخت خود راچاک زده، گفت: «کفر گفت! دیگر ما را چه حاجت به شهود است؟ الحال کفرش را شنیدید!"},{"v":66,"t":"چه مصلحت می‌بینید؟» ایشان در جواب گفتند: «مستوجب قتل است!»"},{"v":67,"t":"آنگاه آب دهان بر رویش انداخته، او را طپانچه می‌زدند و بعضی سیلی زده،"},{"v":68,"t":"می‌گفتند: «ای مسیح، به ما نبوت کن! کیست که تو را زده است؟»"},{"v":69,"t":"اما پطرس در ایوان بیرون نشسته بود که ناگاه کنیزکی نزد وی آمده، گفت: «تو هم با عیسی جلیلی بودی!»"},{"v":70,"t":"او روبروی همه انکارنموده، گفت: «نمی دانم چه می‌گویی!»"},{"v":71,"t":"و چون به دهلیز بیرون رفت، کنیزی دیگر او را دیده، به حاضرین گفت: «این شخص نیز از رفقای عیسی ناصری است!»"},{"v":72,"t":"باز قسم خورده، انکار نمود که «این مرد را نمی شناسم.»"},{"v":73,"t":"بعد از چندی، آنانی که ایستاده بودند پیش آمده، پطرس را گفتند: «البته تو هم از اینها هستی زیرا که لهجه تو بر تودلالت می‌نماید!»"},{"v":74,"t":"پس آغاز لعن کردن و قسم خوردن نمود که «این شخص را نمی شناسم.» ودر ساعت خروس بانگ زد"},{"v":75,"t":"آنگاه پطرس سخن عیسی را به یاد آورد که گفته بود: قبل از بانگ زدن خروس، سه مرتبه مرا انکار خواهی کرد.» پس بیرون رفته زار‌زار بگریست."}]},"27":{"fa":[{"v":1,"t":"و چون صبح شد، همه روسای کهنه ومشایخ قوم بر عیسی شورا کردند که اورا هلاک سازند."},{"v":2,"t":"پس او را بند نهاده، بردند و به پنطیوس پیلاطس والی تسلیم نمودند."},{"v":3,"t":"در آن هنگام، چون یهودا تسلیم‌کننده او دید که بر او فتوا دادند، پشیمان شده، سی پاره نقره را به روسای کهنه و مشایخ رد کرده،"},{"v":4,"t":"گفت: «گناه کردم که خون بیگناهی را تسلیم نمودم.» گفتند: «ما را چه، خود دانی!»"},{"v":5,"t":"پس آن نقره را درهیکل انداخته، روانه شد و رفته خود را خفه نمود."},{"v":6,"t":"اما روسای کهنه نقره را بر داشته، گفتند: «انداختن این در بیت‌المال جایز نیست زیرا خونبها است.»"},{"v":7,"t":"پس شورا نموده، به آن مبلغ، مزرعه کوزه‌گر را بجهت مقبره غرباءخریدند."},{"v":8,"t":"از آن جهت، آن مزرعه تا امروزبحقل الدم مشهور است."},{"v":9,"t":"آنگاه سخنی که به زبان ارمیای نبی گفته شده بود تمام گشت که «سی پاره نقره را برداشتند، بهای آن قیمت کرده شده‌ای که بعضی از بنی‌اسرائیل بر او قیمت گذاردند."},{"v":10,"t":"و آنها را بجهت مزرعه کوزه‌گر دادند، چنانکه خداوند به من گفت.»"},{"v":11,"t":"اما عیسی در حضور والی ایستاده بود. پس والی از او پرسیده، گفت: «آیا تو پادشاه یهودهستی؟» عیسی بدو گفت: «تو می‌گویی!»"},{"v":12,"t":"وچون روسای کهنه و مشایخ از او شکایت می‌کردند، هیچ جواب نمی داد."},{"v":13,"t":"پس پیلاطس وی را گفت: «نمی شنوی چقدر بر تو شهادت می‌دهند؟»"},{"v":14,"t":"اما در جواب وی، یک سخن هم نگفت، بقسمی که والی بسیار متعجب شد."},{"v":15,"t":"و در هر عیدی، رسم والی این بود که یک زندانی، هر‌که را می‌خواستند، برای جماعت آزاد می‌کرد."},{"v":16,"t":"و در آن وقت، زندانی مشهور، برابا نام داشت."},{"v":17,"t":"پس چون مردم جمع شدند، پیلاطس ایشان را گفت: «که را می‌خواهید برای شما آزاد کنم؟ برابا یا عیسی مشهور به مسیح را؟»"},{"v":18,"t":"زیرا که دانست او را از حسد تسلیم کرده بودند."},{"v":19,"t":"چون بر مسند نشسته بود، زنش نزد اوفرستاده، گفت: «با این مرد عادل تو را کاری نباشد، زیرا که امروز در خواب درباره او زحمت بسیار بردم.»"},{"v":20,"t":"اما روسای کهنه و مشایخ، قوم را بر این ترغیب نمودند که برابا را بخواهند و عیسی راهلاک سازند."},{"v":21,"t":"پس والی بدیشان متوجه شده، گفت: «کدام‌یک از این دو نفر را می‌خواهیدبجهت شما رها کنم؟ گفتند: «برابا را.»"},{"v":22,"t":"پیلاطس بدیشان گفت: «پس با عیسی مشهور به مسیح چه کنم؟» جمیع گفتند: «مصلوب شود!»"},{"v":23,"t":"والی گفت: «چرا؟ چه بدی کرده است؟» ایشان بیشترفریاد زده، گفتند: «مصلوب شود!»"},{"v":24,"t":"چون پیلاطس دید که ثمری ندارد بلکه آشوب زیاده می‌گردد، آب طلبیده، پیش مردم دست خود راشسته گفت: «من بری هستم از خون این شخص عادل. شما ببینید.»"},{"v":25,"t":"تمام قوم در جواب گفتند: «خون او بر ما و فرزندان ما باد!»"},{"v":26,"t":"آنگاه برابا رابرای ایشان آزاد کرد و عیسی را تازیانه زده، سپرد تا او را مصلوب کنند."},{"v":27,"t":"آنگاه سپاهیان والی، عیسی را به دیوانخانه برده، تمامی فوج را گرد وی فراهم آوردند."},{"v":28,"t":"واو را عریان ساخته، لباس قرمزی بدو پوشانیدند،"},{"v":29,"t":"و تاجی از خار بافته، بر سرش گذاردند و نی بدست راست او دادند و پیش وی زانو زده، استهزاکنان او را می‌گفتند: «سلام‌ای پادشاه یهود!»"},{"v":30,"t":"و آب دهان بر وی افکنده، نی را گرفته بر سرش می‌زدند."},{"v":31,"t":"و بعد از آنکه او را استهزاکرده بودند، آن لباس را از وی کنده، جامه خودش را پوشانیدند و او را بجهت مصلوب نمودن بیرون بردند."},{"v":32,"t":"و چون بیرون می‌رفتند، شخصی قیروانی شمعون نام را یافته، او را بجهت بردن صلیب مجبور کردند."},{"v":33,"t":"و چون به موضعی که به جلجتایعنی کاسه سر مسمی بود رسیدند،"},{"v":34,"t":"سرکه ممزوج به مر بجهت نوشیدن بدو دادند. اما چون چشید، نخواست که بنوشد."},{"v":35,"t":"پس او را مصلوب نموده، رخت او راتقسیم نمودند و بر آنها قرعه انداختند تا آنچه به زبان نبی گفته شده بود تمام شود که «رخت مرا درمیان خود تقسیم کردند و بر لباس من قرعه انداختند.»"},{"v":36,"t":"و در آنجا به نگاهبانی او نشستند."},{"v":37,"t":"و تقصیر نامه او را نوشته، بالای سرش آویختند که «این است عیسی، پادشاه یهود!»"},{"v":38,"t":"آنگاه دو دزد یکی بر دست راست و دیگری برچپش با وی مصلوب شدند."},{"v":39,"t":"و راهگذاران سرهای خود را جنبانیده، کفر گویان"},{"v":40,"t":"می‌گفتند: «ای کسی‌که هیکل را خراب می‌کنی و در سه روزآن را می‌سازی، خود را نجات ده. اگر پسر خداهستی، از صلیب فرود بیا!»"},{"v":41,"t":"همچنین نیزروسای کهنه با کاتبان و مشایخ استهزاکنان می‌گفتند:"},{"v":42,"t":"«دیگران را نجات داد، اما نمی تواندخود را برهاند. اگر پادشاه اسرائیل است، اکنون ازصلیب فرود آید تا بدو ایمان آوریم!"},{"v":43,"t":"بر خداتوکل نمود، اکنون او را نجات دهد، اگر بدورغبت دارد زیرا گفت پسر خدا هستم!»"},{"v":44,"t":"وهمچنین آن دو دزد نیز که با وی مصلوب بودند، او را دشنام می‌دادند."},{"v":45,"t":"و از ساعت ششم تا ساعت نهم، تاریکی تمام زمین را فرو گرفت."},{"v":46,"t":"و نزدیک به ساعت نهم، عیسی به آواز بلند صدا زده گفت: «ایلی ایلی لما سبقتنی.» یعنی الهی الهی مرا چرا ترک کردی."},{"v":47,"t":"اما بعضی از حاضرین چون این را شنیدند، گفتند که او الیاس را می‌خواند."},{"v":48,"t":"در ساعت یکی از آن میان دویده، اسفنجی را گرفت و آن را پر ازسرکه کرده، بر سر نی گذارد و نزد او داشت تابنوشد."},{"v":49,"t":"و دیگران گفتند: «بگذار تا ببینیم که آیاالیاس می‌آید او را برهاند.»"},{"v":50,"t":"عیسی باز به آوازبلند صیحه زده، روح را تسلیم نمود."},{"v":51,"t":"که ناگاه پرده هیکل از سر تا پا دو پاره شد و زمین متزلزل وسنگها شکافته گردید،"},{"v":52,"t":"و قبرها گشاده شد وبسیاری از بدنهای مقدسین که آرامیده بودندبرخاستند،"},{"v":53,"t":"و بعد از برخاستن وی، از قبوربرآمده، به شهر مقدس رفتند و بر بسیاری ظاهرشدند."},{"v":54,"t":"اما یوزباشی و رفقایش که عیسی رانگاهبانی می‌کردند، چون زلزله و این وقایع رادیدند، بینهایت ترسان شده، گفتند: «فی الواقع این شخص پسر خدا بود.»"},{"v":55,"t":"و در آنجا زنان بسیاری که از جلیل در عقب عیسی آمده بودند تا او راخدمت کنند، از دور نظاره می‌کردند،"},{"v":56,"t":"که از آن جمله، مریم مجدلیه بود و مریم مادر یعقوب ویوشاء و مادر پسران زبدی."},{"v":57,"t":"اما چون وقت عصر رسید، شخصی دولتمند از اهل رامه، یوسف نام که او نیز ازشاگردان عیسی بود آمد،"},{"v":58,"t":"و نزد پیلاطس رفته، جسد عیسی را خواست. آنگاه پیلاطس فرمان داد که داده شود."},{"v":59,"t":"پس یوسف جسد را برداشته، آن را در کتان پاک پیچیده،"},{"v":60,"t":"او را در قبری نو که برای خود از سنگ تراشیده بود، گذارد و سنگی بزرگ بر سر آن غلطانیده، برفت."},{"v":61,"t":"و مریم مجدلیه و مریم دیگر در آنجا، در مقابل قبرنشسته بودند."},{"v":62,"t":"و در فردای آن روز که بعد از روز تهیه بودروسای کهنه و فریسیان نزد پیلاطس جمع شده،"},{"v":63,"t":"گفتند: «ای آقا ما را یاد است که آن گمراه‌کننده وقتی که زنده بود گفت: “بعد از سه روزبرمی خیزم.”"},{"v":64,"t":"پس بفرما قبر را تا سه روزنگاهبانی کنند مبادا شاگردانش در شب آمده، اورا بدزدند و به مردم گویند که از مردگان برخاسته است و گمراهی آخر، از اول بدتر شود.»"},{"v":65,"t":"پیلاطس بدیشان فرمود: «شما کشیکچیان دارید. بروید چنانکه دانید، محافظت کنید.»"},{"v":66,"t":"پس رفتند و سنگ را مختوم ساخته، قبر را باکشیکچیان محافظت نمودند."}]},"28":{"fa":[{"v":1,"t":"و بعد از سبت، هنگام فجر، روز اول هفته، مریم مجدلیه و مریم دیگربجهت دیدن قبر‌آمدند."},{"v":2,"t":"که ناگاه زلزله‌ای عظیم حادث شد از آنرو که فرشته خداوند از آسمان نزول کرده، آمد و سنگ را از در قبر غلطانیده، برآن بنشست."},{"v":3,"t":"و صورت او مثل برق و لباسش چون برف سفید بود."},{"v":4,"t":"و از ترس او کشیکچیان به لرزه درآمده، مثل مرده گردیدند."},{"v":5,"t":"اما فرشته به زنان متوجه شده، گفت: شما ترسان مباشید!"},{"v":6,"t":"دراینجا نیست زیرا چنانکه گفته بود برخاسته است. بیایید جایی که خداوند خفته بود ملاحظه کنید،"},{"v":7,"t":"و به زودی رفته شاگردانش را خبر دهید که ازمردگان برخاسته است. اینک پیش از شما به جلیل می‌رود. در آنجا او را خواهید دید. اینک شما را گفتم.»"},{"v":8,"t":"پس، از قبر با ترس و خوشی عظیم به زودی روانه شده، رفتند تا شاگردان او را اطلاع دهند."},{"v":9,"t":"ودر هنگامی که بجهت اخبار شاگردان او می‌رفتند، ناگاه عیسی بدیشان برخورده، گفت: «سلام برشما باد!» پس پیش آمده، به قدمهای اوچسبیده، او را پرستش کردند."},{"v":10,"t":"آنگاه عیسی بدیشان گفت: «مترسید! رفته، برادرانم رابگویید که به جلیل بروند که در آنجا مرا خواهنددید.»"},{"v":11,"t":"و چون ایشان می‌رفتند، ناگاه بعضی ازکشیکچیان به شهر شده، روسای کهنه را از همه این وقایع مطلع ساختند."},{"v":12,"t":"ایشان با مشایخ جمع شده، شورا نمودند و نقره بسیار به سپاهیان داده،"},{"v":13,"t":"گفتند: «بگویید که شبانگاه شاگردانش آمده، وقتی که ما در خواب بودیم او را دزدیدند."},{"v":14,"t":"وهرگاه این سخن گوش زد والی شود، همانا ما او رابرگردانیم و شما را مطمئن سازیم.»"},{"v":15,"t":"ایشان پول را گرفته، چنانکه تعلیم یافتند کردند و این سخن تاامروز در میان یهود منتشر است."},{"v":16,"t":"اما یازده رسول به جلیل، بر کوهی که عیسی ایشان را نشان داده بود رفتند."},{"v":17,"t":"و چون او را دیدند، پرستش نمودند. لیکن بعضی شک کردند."},{"v":18,"t":"پس عیسی پیش آمده، بدیشان خطاب کرده، گفت: «تمامی قدرت در آسمان و بر زمین به من داده شده است."},{"v":19,"t":"پس رفته، همه امت‌ها را شاگرد سازید و ایشان رابه اسم اب و ابن و روح‌القدس تعمید دهید."},{"v":20,"t":"وایشان را تعلیم دهید که همه اموری را که به شما حکم کرده‌ام حفظ کنند. و اینک من هرروزه تا انقضای عالم همراه شما می‌باشم.» آمین."}]}});
